    fn diagnose_runtime_db_replay_checkpoint_row_meta_read_only(
        runtime_db_path: &Path,
        deadline: Instant,
        include_state_json_bytes: bool,
    ) -> Result<ReplayCheckpointRuntimeDbDiagnostic> {
        #[derive(Debug, Clone)]
        struct ReplayCheckpointRuntimeDbMetaProgressSnapshot {
            row_meta: PersistedReplayCheckpointRowMeta,
            meta_open_db_elapsed_ms: Option<u64>,
            meta_check_table_exists_elapsed_ms: Option<u64>,
            meta_query_elapsed_ms: Option<u64>,
            meta_parse_phase_elapsed_ms: Option<u64>,
            meta_parse_updated_at_elapsed_ms: Option<u64>,
            meta_state_json_bytes_eval_elapsed_ms: Option<u64>,
        }

        impl ReplayCheckpointRuntimeDbMetaProgressSnapshot {
            fn new() -> Self {
                Self {
                    row_meta: DiscoveryService::unknown_persisted_rebuild_row_meta(),
                    meta_open_db_elapsed_ms: None,
                    meta_check_table_exists_elapsed_ms: None,
                    meta_query_elapsed_ms: None,
                    meta_parse_phase_elapsed_ms: None,
                    meta_parse_updated_at_elapsed_ms: None,
                    meta_state_json_bytes_eval_elapsed_ms: None,
                }
            }
        }

        #[derive(Debug)]
        enum ReplayCheckpointRuntimeDbMetaWorkerMessage {
            Entered(ReplayCheckpointRuntimeDbMetaDiagnosticSubstage),
            Snapshot(ReplayCheckpointRuntimeDbMetaProgressSnapshot),
            Finished(Result<(), String>),
        }

        let meta_started_at = Instant::now();
        let mut diagnostic = ReplayCheckpointRuntimeDbDiagnostic {
            diagnostic_stage: ReplayCheckpointRuntimeDbDiagnosticStage::LoadPersistedRebuildRowMeta,
            diagnostic_meta_substage: Some(
                ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::OpenDbForMetaReadOnly,
            ),
            diagnostic_budget_exhausted: false,
            diagnostic_skipped_stages: Vec::new(),
            diagnostic_open_db_elapsed_ms: None,
            diagnostic_load_row_meta_elapsed_ms: None,
            diagnostic_load_row_elapsed_ms: None,
            diagnostic_parse_state_elapsed_ms: None,
            diagnostic_classify_blocker_elapsed_ms: None,
            diagnostic_total_elapsed_ms: 0,
            meta_state_json_bytes_requested: include_state_json_bytes,
            meta_open_db_elapsed_ms: None,
            meta_check_table_exists_elapsed_ms: None,
            meta_query_elapsed_ms: None,
            meta_parse_phase_elapsed_ms: None,
            meta_parse_updated_at_elapsed_ms: None,
            meta_state_json_bytes_eval_elapsed_ms: None,
            meta_total_elapsed_ms: None,
            row_meta: Self::unknown_persisted_rebuild_row_meta(),
            inspection: None,
            blocker_explanation: None,
        };
        let (tx, rx) = mpsc::sync_channel(16);
        let runtime_db_path = runtime_db_path.to_path_buf();
        thread::spawn(move || {
            let send_finished = |result: Result<(), anyhow::Error>| {
                let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Finished(
                    result.map_err(|error| format!("{error:#}")),
                ));
            };
            let mut snapshot = ReplayCheckpointRuntimeDbMetaProgressSnapshot::new();

            let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(
                ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::OpenDbForMetaReadOnly,
            ));
            let open_started_at = Instant::now();
            let store = match SqliteStore::open_read_only(&runtime_db_path).with_context(|| {
                format!(
                    "failed opening runtime sqlite db read-only {}",
                    runtime_db_path.display()
                )
            }) {
                Ok(store) => store,
                Err(error) => {
                    send_finished(Err(error));
                    return;
                }
            };
            snapshot.meta_open_db_elapsed_ms =
                Some(open_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
            if tx
                .send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                    snapshot.clone(),
                ))
                .is_err()
            {
                return;
            }

            let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(
                ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::CheckTableExists,
            ));
            let check_started_at = Instant::now();
            let table_exists = match Self::replay_checkpoint_runtime_db_meta_row_exists(&store) {
                Ok(value) => value,
                Err(error) => {
                    send_finished(Err(error));
                    return;
                }
            };
            snapshot.meta_check_table_exists_elapsed_ms =
                Some(check_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
            if !table_exists {
                snapshot.row_meta = Self::missing_persisted_rebuild_row_meta();
                let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                    snapshot,
                ));
                let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Finished(Ok(())));
                return;
            }
            if tx
                .send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                    snapshot.clone(),
                ))
                .is_err()
            {
                return;
            }

            let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(
                ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::QueryRowMeta,
            ));
            let query_started_at = Instant::now();
            let raw_meta = match Self::replay_checkpoint_runtime_db_meta_query_lite_raw(&store) {
                Ok(value) => value,
                Err(error) => {
                    send_finished(Err(error));
                    return;
                }
            };
            snapshot.meta_query_elapsed_ms =
                Some(query_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
            let raw_meta = if let Some(raw_meta) = raw_meta {
                snapshot.row_meta.persisted_rebuild_row_exists = Some(true);
                if tx
                    .send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                        snapshot.clone(),
                    ))
                    .is_err()
                {
                    return;
                }
                raw_meta
            } else {
                snapshot.row_meta = Self::missing_persisted_rebuild_row_meta();
                let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                    snapshot,
                ));
                let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Finished(Ok(())));
                return;
            };

            let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(
                ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::ParsePhase,
            ));
            let parse_phase_started_at = Instant::now();
            let parsed_phase =
                match Self::parse_persisted_rebuild_row_meta_phase_read_only(&raw_meta.phase_raw) {
                    Ok(value) => value,
                    Err(error) => {
                        send_finished(Err(error));
                        return;
                    }
                };
            snapshot.meta_parse_phase_elapsed_ms = Some(
                parse_phase_started_at
                    .elapsed()
                    .as_millis()
                    .min(u64::MAX as u128) as u64,
            );
            snapshot.row_meta.persisted_rebuild_row_phase = Some(parsed_phase.as_str().to_string());
            if tx
                .send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                    snapshot.clone(),
                ))
                .is_err()
            {
                return;
            }

            let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(
                ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::ParseUpdatedAt,
            ));
            let parse_updated_at_started_at = Instant::now();
            let parsed_updated_at =
                match Self::parse_persisted_rebuild_row_meta_updated_at_read_only(
                    &raw_meta.updated_at_raw,
                ) {
                    Ok(value) => value,
                    Err(error) => {
                        send_finished(Err(error));
                        return;
                    }
                };
            snapshot.meta_parse_updated_at_elapsed_ms = Some(
                parse_updated_at_started_at
                    .elapsed()
                    .as_millis()
                    .min(u64::MAX as u128) as u64,
            );
            snapshot.row_meta.persisted_rebuild_row_updated_at = Some(parsed_updated_at);
            if tx
                .send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                    snapshot.clone(),
                ))
                .is_err()
            {
                return;
            }

            if include_state_json_bytes {
                let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(
                    ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::EvaluateStateJsonBytes,
                ));
                let size_started_at = Instant::now();
                let state_json_bytes =
                    match Self::replay_checkpoint_runtime_db_meta_state_json_bytes(&store) {
                        Ok(value) => value,
                        Err(error) => {
                            send_finished(Err(error));
                            return;
                        }
                    };
                snapshot.meta_state_json_bytes_eval_elapsed_ms =
                    Some(size_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
                snapshot.row_meta.persisted_rebuild_state_json_bytes = state_json_bytes;
                if tx
                    .send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(
                        snapshot.clone(),
                    ))
                    .is_err()
                {
                    return;
                }
            }

            let _ = tx.send(ReplayCheckpointRuntimeDbMetaWorkerMessage::Finished(Ok(())));
        });

        loop {
            let remaining = deadline.saturating_duration_since(Instant::now());
            if remaining.is_zero() {
                diagnostic.diagnostic_budget_exhausted = true;
                diagnostic.meta_total_elapsed_ms =
                    Some(meta_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
                diagnostic.diagnostic_total_elapsed_ms = diagnostic.meta_total_elapsed_ms.unwrap();
                return Ok(diagnostic);
            }

            match rx.recv_timeout(remaining) {
                Ok(ReplayCheckpointRuntimeDbMetaWorkerMessage::Entered(substage)) => {
                    diagnostic.diagnostic_meta_substage = Some(substage);
                }
                Ok(ReplayCheckpointRuntimeDbMetaWorkerMessage::Snapshot(snapshot)) => {
                    diagnostic.row_meta = snapshot.row_meta;
                    diagnostic.meta_open_db_elapsed_ms = snapshot.meta_open_db_elapsed_ms;
                    diagnostic.meta_check_table_exists_elapsed_ms =
                        snapshot.meta_check_table_exists_elapsed_ms;
                    diagnostic.meta_query_elapsed_ms = snapshot.meta_query_elapsed_ms;
                    diagnostic.meta_parse_phase_elapsed_ms = snapshot.meta_parse_phase_elapsed_ms;
                    diagnostic.meta_parse_updated_at_elapsed_ms =
                        snapshot.meta_parse_updated_at_elapsed_ms;
                    diagnostic.meta_state_json_bytes_eval_elapsed_ms =
                        snapshot.meta_state_json_bytes_eval_elapsed_ms;
                }
                Ok(ReplayCheckpointRuntimeDbMetaWorkerMessage::Finished(result)) => {
                    if let Err(error) = result {
                        return Err(anyhow!(
                            "runtime-db-only replay checkpoint diagnostic meta worker failed: {error}"
                        ));
                    }
                    diagnostic.diagnostic_meta_substage =
                        Some(ReplayCheckpointRuntimeDbMetaDiagnosticSubstage::Complete);
                    diagnostic.meta_total_elapsed_ms =
                        Some(meta_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
                    diagnostic.diagnostic_load_row_meta_elapsed_ms =
                        diagnostic.meta_total_elapsed_ms;
                    diagnostic.diagnostic_total_elapsed_ms =
                        diagnostic.meta_total_elapsed_ms.unwrap();
                    diagnostic.diagnostic_stage =
                        ReplayCheckpointRuntimeDbDiagnosticStage::Complete;
                    return Ok(diagnostic);
                }
                Err(mpsc::RecvTimeoutError::Timeout) => {
                    diagnostic.diagnostic_budget_exhausted = true;
                    diagnostic.meta_total_elapsed_ms =
                        Some(meta_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
                    diagnostic.diagnostic_total_elapsed_ms =
                        diagnostic.meta_total_elapsed_ms.unwrap();
                    return Ok(diagnostic);
                }
                Err(mpsc::RecvTimeoutError::Disconnected) => {
                    return Err(anyhow!(
                        "runtime-db-only replay checkpoint diagnostic meta worker disconnected before returning a result"
                    ));
                }
            }
        }
    }

    pub fn diagnose_runtime_db_replay_checkpoint_read_only(
        runtime_db_path: &Path,
        mode: ReplayCheckpointRuntimeDbOnlyMode,
        budget_ms: u64,
    ) -> Result<ReplayCheckpointRuntimeDbDiagnostic> {
        let started_at = Instant::now();
        let deadline = started_at + StdDuration::from_millis(budget_ms);
        let mut diagnostic = ReplayCheckpointRuntimeDbDiagnostic {
            diagnostic_stage: ReplayCheckpointRuntimeDbDiagnosticStage::OpenDbReadOnly,
            diagnostic_meta_substage: None,
            diagnostic_budget_exhausted: false,
            diagnostic_skipped_stages: Vec::new(),
            diagnostic_open_db_elapsed_ms: None,
            diagnostic_load_row_meta_elapsed_ms: None,
            diagnostic_load_row_elapsed_ms: None,
            diagnostic_parse_state_elapsed_ms: None,
            diagnostic_classify_blocker_elapsed_ms: None,
            diagnostic_total_elapsed_ms: 0,
            meta_state_json_bytes_requested: matches!(
                mode,
                ReplayCheckpointRuntimeDbOnlyMode::RowMeta
            ),
            meta_open_db_elapsed_ms: None,
            meta_check_table_exists_elapsed_ms: None,
            meta_query_elapsed_ms: None,
            meta_parse_phase_elapsed_ms: None,
            meta_parse_updated_at_elapsed_ms: None,
            meta_state_json_bytes_eval_elapsed_ms: None,
            meta_total_elapsed_ms: None,
            row_meta: Self::unknown_persisted_rebuild_row_meta(),
            inspection: None,
            blocker_explanation: None,
        };

        let runtime_db_path = runtime_db_path.to_path_buf();
        let Some(((), open_elapsed_ms)) =
            Self::replay_checkpoint_runtime_db_diagnostic_stage_timeout(
                ReplayCheckpointRuntimeDbDiagnosticStage::OpenDbReadOnly,
                deadline,
                {
                    let runtime_db_path = runtime_db_path.clone();
                    move || {
                        SqliteStore::open_read_only(&runtime_db_path).with_context(|| {
                            format!(
                                "failed opening runtime sqlite db read-only {}",
                                runtime_db_path.display()
                            )
                        })?;
                        Ok(())
                    }
                },
            )?
        else {
            diagnostic.diagnostic_budget_exhausted = true;
            diagnostic.diagnostic_stage = ReplayCheckpointRuntimeDbDiagnosticStage::OpenDbReadOnly;
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(
                    mode,
                    None,
                    Some(ReplayCheckpointRuntimeDbDiagnosticStage::OpenDbReadOnly),
                );
            return Ok(diagnostic);
        };
        diagnostic.diagnostic_open_db_elapsed_ms = Some(open_elapsed_ms);

        let meta_diagnostic = Self::diagnose_runtime_db_replay_checkpoint_row_meta_read_only(
            &runtime_db_path,
            deadline,
            matches!(mode, ReplayCheckpointRuntimeDbOnlyMode::RowMeta),
        )?;
        diagnostic.diagnostic_stage = meta_diagnostic.diagnostic_stage;
        diagnostic.diagnostic_meta_substage = meta_diagnostic.diagnostic_meta_substage;
        diagnostic.diagnostic_budget_exhausted = meta_diagnostic.diagnostic_budget_exhausted;
        diagnostic.diagnostic_load_row_meta_elapsed_ms =
            meta_diagnostic.diagnostic_load_row_meta_elapsed_ms;
        diagnostic.meta_state_json_bytes_requested =
            meta_diagnostic.meta_state_json_bytes_requested;
        diagnostic.meta_open_db_elapsed_ms = meta_diagnostic.meta_open_db_elapsed_ms;
        diagnostic.meta_check_table_exists_elapsed_ms =
            meta_diagnostic.meta_check_table_exists_elapsed_ms;
        diagnostic.meta_query_elapsed_ms = meta_diagnostic.meta_query_elapsed_ms;
        diagnostic.meta_parse_phase_elapsed_ms = meta_diagnostic.meta_parse_phase_elapsed_ms;
        diagnostic.meta_parse_updated_at_elapsed_ms =
            meta_diagnostic.meta_parse_updated_at_elapsed_ms;
        diagnostic.meta_state_json_bytes_eval_elapsed_ms =
            meta_diagnostic.meta_state_json_bytes_eval_elapsed_ms;
        diagnostic.meta_total_elapsed_ms = meta_diagnostic.meta_total_elapsed_ms;
        diagnostic.row_meta = meta_diagnostic.row_meta.clone();

        if diagnostic.diagnostic_budget_exhausted {
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(
                    mode,
                    diagnostic.row_meta.persisted_rebuild_row_exists,
                    Some(ReplayCheckpointRuntimeDbDiagnosticStage::LoadPersistedRebuildRowMeta),
                );
            return Ok(diagnostic);
        }

        if matches!(
            mode,
            ReplayCheckpointRuntimeDbOnlyMode::RowMeta
                | ReplayCheckpointRuntimeDbOnlyMode::RowMetaLite
        ) {
            diagnostic.diagnostic_stage = ReplayCheckpointRuntimeDbDiagnosticStage::Complete;
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(mode, None, None);
            return Ok(diagnostic);
        }

        if diagnostic.row_meta.persisted_rebuild_row_exists == Some(false) {
            let inspection = Self::empty_persisted_rebuild_state_inspection();
            if mode == ReplayCheckpointRuntimeDbOnlyMode::Inspect {
                diagnostic.inspection = Some(inspection);
            } else {
                diagnostic.blocker_explanation =
                    Some(Self::explain_publishable_checkpoint_blocker_from_inspection(inspection));
            }
            diagnostic.diagnostic_stage = ReplayCheckpointRuntimeDbDiagnosticStage::Complete;
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(
                    mode,
                    Some(false),
                    None,
                );
            return Ok(diagnostic);
        }

        let Some((row, load_row_elapsed_ms)) =
            Self::replay_checkpoint_runtime_db_diagnostic_stage_timeout(
                ReplayCheckpointRuntimeDbDiagnosticStage::LoadPersistedRebuildRow,
                deadline,
                {
                    let runtime_db_path = runtime_db_path.clone();
                    move || {
                        let store =
                            SqliteStore::open_read_only(&runtime_db_path).with_context(|| {
                                format!(
                                    "failed opening runtime sqlite db read-only {}",
                                    runtime_db_path.display()
                                )
                            })?;
                        store
                            .load_discovery_persisted_rebuild_state_read_only()?
                            .ok_or_else(|| {
                                anyhow!("persisted rebuild row disappeared after metadata load")
                            })
                    }
                },
            )?
        else {
            diagnostic.diagnostic_budget_exhausted = true;
            diagnostic.diagnostic_stage =
                ReplayCheckpointRuntimeDbDiagnosticStage::LoadPersistedRebuildRow;
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(
                    mode,
                    Some(true),
                    Some(ReplayCheckpointRuntimeDbDiagnosticStage::LoadPersistedRebuildRow),
                );
            return Ok(diagnostic);
        };
        diagnostic.diagnostic_load_row_elapsed_ms = Some(load_row_elapsed_ms);

        let Some((parsed, parse_elapsed_ms)) =
            Self::replay_checkpoint_runtime_db_diagnostic_stage_timeout(
                ReplayCheckpointRuntimeDbDiagnosticStage::ParsePersistedRebuildState,
                deadline,
                move || Self::parse_persisted_rebuild_state_row_read_only(row),
            )?
        else {
            diagnostic.diagnostic_budget_exhausted = true;
            diagnostic.diagnostic_stage =
                ReplayCheckpointRuntimeDbDiagnosticStage::ParsePersistedRebuildState;
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(
                    mode,
                    Some(true),
                    Some(ReplayCheckpointRuntimeDbDiagnosticStage::ParsePersistedRebuildState),
                );
            return Ok(diagnostic);
        };
        diagnostic.diagnostic_parse_state_elapsed_ms = Some(parse_elapsed_ms);

        let Some((classification, classify_elapsed_ms)) =
            Self::replay_checkpoint_runtime_db_diagnostic_stage_timeout(
                ReplayCheckpointRuntimeDbDiagnosticStage::ClassifyPublishableCheckpointBlocker,
                deadline,
                move || {
                    Ok::<_, anyhow::Error>(match mode {
                        ReplayCheckpointRuntimeDbOnlyMode::Inspect => {
                            RuntimeDbDiagnosticClassification::Inspection(
                                Self::inspect_parsed_persisted_rebuild_state_read_only(&parsed),
                            )
                        }
                        ReplayCheckpointRuntimeDbOnlyMode::ExplainPublishableCheckpointBlocker => {
                            RuntimeDbDiagnosticClassification::BlockerExplanation(
                                Self::explain_publishable_checkpoint_blocker_from_parsed_read_only(
                                    &parsed,
                                ),
                            )
                        }
                        ReplayCheckpointRuntimeDbOnlyMode::RowMeta
                        | ReplayCheckpointRuntimeDbOnlyMode::RowMetaLite => {
                            unreachable!("handled above")
                        }
                    })
                },
            )?
        else {
            diagnostic.diagnostic_budget_exhausted = true;
            diagnostic.diagnostic_stage =
                ReplayCheckpointRuntimeDbDiagnosticStage::ClassifyPublishableCheckpointBlocker;
            diagnostic.diagnostic_total_elapsed_ms =
                started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
            diagnostic.diagnostic_skipped_stages =
                Self::replay_checkpoint_runtime_db_diagnostic_skipped_stages(
                    mode,
                    Some(true),
                    Some(
                        ReplayCheckpointRuntimeDbDiagnosticStage::ClassifyPublishableCheckpointBlocker,
                    ),
                );
            return Ok(diagnostic);
        };
        diagnostic.diagnostic_classify_blocker_elapsed_ms = Some(classify_elapsed_ms);

        match classification {
            RuntimeDbDiagnosticClassification::Inspection(inspection) => {
                diagnostic.inspection = Some(inspection);
            }
            RuntimeDbDiagnosticClassification::BlockerExplanation(explanation) => {
                diagnostic.blocker_explanation = Some(explanation);
            }
        }

        diagnostic.diagnostic_stage = ReplayCheckpointRuntimeDbDiagnosticStage::Complete;
        diagnostic.diagnostic_total_elapsed_ms =
            started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
        Ok(diagnostic)
    }

    pub fn probe_persisted_rebuild_row_raw_read_only(
        runtime_db_path: &Path,
        budget_ms: u64,
    ) -> Result<RawPersistedRebuildRowProbeDiagnostic> {
        #[derive(Debug, Clone)]
        struct RawProbeSnapshot {
            raw_persisted_rebuild_row_exists: Option<bool>,
            raw_row_meta_query_plan: Option<Vec<String>>,
            raw_row_size_query_plan: Option<Vec<String>>,
            raw_row_meta_query_elapsed_ms: Option<u64>,
            raw_row_size_query_elapsed_ms: Option<u64>,
            raw_row_phase: Option<String>,
            raw_row_updated_at: Option<String>,
            raw_row_state_json_bytes: Option<usize>,
            raw_runtime_db_page_size: Option<usize>,
            raw_runtime_db_page_count: Option<usize>,
            raw_runtime_db_freelist_count: Option<usize>,
            raw_runtime_db_journal_mode: Option<String>,
            raw_runtime_db_locking_mode: Option<String>,
            raw_probe_open_db_elapsed_ms: Option<u64>,
            raw_probe_check_table_exists_elapsed_ms: Option<u64>,
            raw_probe_meta_query_plan_elapsed_ms: Option<u64>,
            raw_probe_meta_query_elapsed_ms: Option<u64>,
            raw_probe_size_query_plan_elapsed_ms: Option<u64>,
            raw_probe_size_query_elapsed_ms: Option<u64>,
            raw_probe_runtime_db_facts_elapsed_ms: Option<u64>,
        }

        impl RawProbeSnapshot {
            fn new() -> Self {
                Self {
                    raw_persisted_rebuild_row_exists: None,
                    raw_row_meta_query_plan: None,
                    raw_row_size_query_plan: None,
                    raw_row_meta_query_elapsed_ms: None,
                    raw_row_size_query_elapsed_ms: None,
                    raw_row_phase: None,
                    raw_row_updated_at: None,
                    raw_row_state_json_bytes: None,
                    raw_runtime_db_page_size: None,
                    raw_runtime_db_page_count: None,
                    raw_runtime_db_freelist_count: None,
                    raw_runtime_db_journal_mode: None,
                    raw_runtime_db_locking_mode: None,
                    raw_probe_open_db_elapsed_ms: None,
                    raw_probe_check_table_exists_elapsed_ms: None,
                    raw_probe_meta_query_plan_elapsed_ms: None,
                    raw_probe_meta_query_elapsed_ms: None,
                    raw_probe_size_query_plan_elapsed_ms: None,
                    raw_probe_size_query_elapsed_ms: None,
                    raw_probe_runtime_db_facts_elapsed_ms: None,
                }
            }
        }

        #[derive(Debug)]
        enum RawProbeWorkerMessage {
            Entered(RawPersistedRebuildRowProbeStage),
            Snapshot(RawProbeSnapshot),
            Finished(Result<(), String>),
        }

        let started_at = Instant::now();
        let deadline = started_at + StdDuration::from_millis(budget_ms);
        let mut diagnostic = RawPersistedRebuildRowProbeDiagnostic {
            raw_probe_stage: RawPersistedRebuildRowProbeStage::OpenDbReadOnly,
            raw_probe_budget_exhausted: false,
            raw_probe_skipped_stages: Vec::new(),
            raw_probe_open_db_elapsed_ms: None,
            raw_probe_check_table_exists_elapsed_ms: None,
            raw_probe_meta_query_plan_elapsed_ms: None,
            raw_probe_meta_query_elapsed_ms: None,
            raw_probe_size_query_plan_elapsed_ms: None,
            raw_probe_size_query_elapsed_ms: None,
            raw_probe_runtime_db_facts_elapsed_ms: None,
            raw_probe_total_elapsed_ms: 0,
            raw_persisted_rebuild_row_exists: None,
            raw_row_meta_query_plan: None,
            raw_row_size_query_plan: None,
            raw_row_meta_query_elapsed_ms: None,
            raw_row_size_query_elapsed_ms: None,
            raw_row_phase: None,
            raw_row_updated_at: None,
            raw_row_state_json_bytes: None,
            raw_runtime_db_page_size: None,
            raw_runtime_db_page_count: None,
            raw_runtime_db_freelist_count: None,
            raw_runtime_db_journal_mode: None,
            raw_runtime_db_locking_mode: None,
            raw_persisted_rebuild_row_reason_class:
                RawPersistedRebuildRowReasonClass::RowMetaQueryUnprovenDueToProbeBudgetExhausted,
            raw_persisted_rebuild_row_explanation:
                "raw persisted rebuild row probe has not completed yet".to_string(),
        };

        let (tx, rx) = mpsc::sync_channel(16);
        let runtime_db_path = runtime_db_path.to_path_buf();
        thread::spawn(move || {
            let send_finished = |result: Result<(), anyhow::Error>| {
                let _ = tx.send(RawProbeWorkerMessage::Finished(
                    result.map_err(|error| format!("{error:#}")),
                ));
            };

            let mut snapshot = RawProbeSnapshot::new();

            let _ = tx.send(RawProbeWorkerMessage::Entered(
                RawPersistedRebuildRowProbeStage::OpenDbReadOnly,
            ));
            let open_started_at = Instant::now();
            let store = match SqliteStore::open_read_only(&runtime_db_path).with_context(|| {
                format!(
                    "failed opening runtime sqlite db read-only {}",
                    runtime_db_path.display()
                )
            }) {
                Ok(store) => store,
                Err(error) => {
                    send_finished(Err(error));
                    return;
                }
            };
            snapshot.raw_probe_open_db_elapsed_ms =
                Some(open_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
            if tx
                .send(RawProbeWorkerMessage::Snapshot(snapshot.clone()))
                .is_err()
            {
                return;
            }

            let _ = tx.send(RawProbeWorkerMessage::Entered(
                RawPersistedRebuildRowProbeStage::CheckTableExists,
            ));
            let check_started_at = Instant::now();
            let table_exists = match Self::replay_checkpoint_runtime_db_meta_row_exists(&store) {
                Ok(value) => value,
                Err(error) => {
                    send_finished(Err(error));
                    return;
                }
            };
            snapshot.raw_probe_check_table_exists_elapsed_ms =
                Some(check_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
            if !table_exists {
                snapshot.raw_persisted_rebuild_row_exists = Some(false);
            }
            if tx
                .send(RawProbeWorkerMessage::Snapshot(snapshot.clone()))
                .is_err()
            {
                return;
            }

            if table_exists {
                let _ = tx.send(RawProbeWorkerMessage::Entered(
                    RawPersistedRebuildRowProbeStage::ExplainMetaQueryPlan,
                ));
                let meta_plan_started_at = Instant::now();
                #[cfg(test)]
                if let Some(delay_ms) =
                    take_test_force_replay_checkpoint_raw_probe_meta_plan_delay_ms()
                {
                    thread::sleep(StdDuration::from_millis(delay_ms));
                }
                let meta_query_plan = match store
                    .explain_discovery_persisted_rebuild_state_meta_query_plan_after_table_exists_read_only()
                {
                    Ok(value) => value,
                    Err(error) => {
                        send_finished(Err(error));
                        return;
                    }
                };
                snapshot.raw_probe_meta_query_plan_elapsed_ms = Some(
                    meta_plan_started_at
                        .elapsed()
                        .as_millis()
                        .min(u64::MAX as u128) as u64,
                );
                snapshot.raw_row_meta_query_plan = Some(meta_query_plan);
                if tx
                    .send(RawProbeWorkerMessage::Snapshot(snapshot.clone()))
                    .is_err()
                {
                    return;
                }

                let _ = tx.send(RawProbeWorkerMessage::Entered(
                    RawPersistedRebuildRowProbeStage::QueryRowMeta,
                ));
                let meta_query_started_at = Instant::now();
                let raw_meta = match Self::replay_checkpoint_runtime_db_meta_query_lite_raw(&store)
                {
                    Ok(value) => value,
                    Err(error) => {
                        send_finished(Err(error));
                        return;
                    }
                };
                snapshot.raw_probe_meta_query_elapsed_ms = Some(
                    meta_query_started_at
                        .elapsed()
                        .as_millis()
                        .min(u64::MAX as u128) as u64,
                );
                snapshot.raw_row_meta_query_elapsed_ms = snapshot.raw_probe_meta_query_elapsed_ms;
                if let Some(raw_meta) = raw_meta {
                    snapshot.raw_persisted_rebuild_row_exists = Some(true);
                    snapshot.raw_row_phase = Some(raw_meta.phase_raw);
                    snapshot.raw_row_updated_at = Some(raw_meta.updated_at_raw);
                } else {
                    snapshot.raw_persisted_rebuild_row_exists = Some(false);
                }
                if tx
                    .send(RawProbeWorkerMessage::Snapshot(snapshot.clone()))
                    .is_err()
                {
                    return;
                }

                let _ = tx.send(RawProbeWorkerMessage::Entered(
                    RawPersistedRebuildRowProbeStage::ExplainSizeQueryPlan,
                ));
                let size_plan_started_at = Instant::now();
                let size_query_plan = match store
                    .explain_discovery_persisted_rebuild_state_size_query_plan_after_table_exists_read_only()
                {
                    Ok(value) => value,
                    Err(error) => {
                        send_finished(Err(error));
                        return;
                    }
                };
                snapshot.raw_probe_size_query_plan_elapsed_ms = Some(
                    size_plan_started_at
                        .elapsed()
                        .as_millis()
                        .min(u64::MAX as u128) as u64,
                );
                snapshot.raw_row_size_query_plan = Some(size_query_plan);
                if tx
                    .send(RawProbeWorkerMessage::Snapshot(snapshot.clone()))
                    .is_err()
                {
                    return;
                }

                let _ = tx.send(RawProbeWorkerMessage::Entered(
                    RawPersistedRebuildRowProbeStage::QueryRowStateJsonSize,
                ));
                let size_query_started_at = Instant::now();
                let state_json_bytes =
                    match Self::replay_checkpoint_runtime_db_meta_state_json_bytes(&store) {
                        Ok(value) => value,
                        Err(error) => {
                            send_finished(Err(error));
                            return;
                        }
                    };
                snapshot.raw_probe_size_query_elapsed_ms = Some(
                    size_query_started_at
                        .elapsed()
                        .as_millis()
                        .min(u64::MAX as u128) as u64,
                );
                snapshot.raw_row_size_query_elapsed_ms = snapshot.raw_probe_size_query_elapsed_ms;
                snapshot.raw_row_state_json_bytes = state_json_bytes;
                if tx
                    .send(RawProbeWorkerMessage::Snapshot(snapshot.clone()))
                    .is_err()
                {
                    return;
                }
            }

            let _ = tx.send(RawProbeWorkerMessage::Entered(
                RawPersistedRebuildRowProbeStage::LoadRuntimeDbFacts,
            ));
            let facts_started_at = Instant::now();
            let facts = match store.sqlite_read_only_probe_facts() {
                Ok(value) => value,
                Err(error) => {
                    send_finished(Err(error));
                    return;
                }
            };
            snapshot.raw_probe_runtime_db_facts_elapsed_ms =
                Some(facts_started_at.elapsed().as_millis().min(u64::MAX as u128) as u64);
            snapshot.raw_runtime_db_page_size = Some(facts.page_size);
            snapshot.raw_runtime_db_page_count = Some(facts.page_count);
            snapshot.raw_runtime_db_freelist_count = Some(facts.freelist_count);
            snapshot.raw_runtime_db_journal_mode = Some(facts.journal_mode);
            snapshot.raw_runtime_db_locking_mode = Some(facts.locking_mode);
            if tx.send(RawProbeWorkerMessage::Snapshot(snapshot)).is_err() {
                return;
            }

            let _ = tx.send(RawProbeWorkerMessage::Finished(Ok(())));
        });

        loop {
            let remaining = deadline.saturating_duration_since(Instant::now());
            if remaining.is_zero() {
                diagnostic.raw_probe_budget_exhausted = true;
                diagnostic.raw_probe_total_elapsed_ms =
                    started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
                diagnostic.raw_probe_skipped_stages =
                    Self::raw_persisted_rebuild_row_skipped_stages(
                        diagnostic.raw_probe_stage,
                        true,
                    );
                let (reason_class, explanation) =
                    Self::classify_raw_persisted_rebuild_row_probe(&diagnostic);
                diagnostic.raw_persisted_rebuild_row_reason_class = reason_class;
                diagnostic.raw_persisted_rebuild_row_explanation = explanation;
                return Ok(diagnostic);
            }

            match rx.recv_timeout(remaining) {
                Ok(RawProbeWorkerMessage::Entered(stage)) => {
                    diagnostic.raw_probe_stage = stage;
                }
                Ok(RawProbeWorkerMessage::Snapshot(snapshot)) => {
                    diagnostic.raw_persisted_rebuild_row_exists =
                        snapshot.raw_persisted_rebuild_row_exists;
                    diagnostic.raw_row_meta_query_plan = snapshot.raw_row_meta_query_plan;
                    diagnostic.raw_row_size_query_plan = snapshot.raw_row_size_query_plan;
                    diagnostic.raw_row_meta_query_elapsed_ms =
                        snapshot.raw_row_meta_query_elapsed_ms;
                    diagnostic.raw_row_size_query_elapsed_ms =
                        snapshot.raw_row_size_query_elapsed_ms;
                    diagnostic.raw_row_phase = snapshot.raw_row_phase;
                    diagnostic.raw_row_updated_at = snapshot.raw_row_updated_at;
                    diagnostic.raw_row_state_json_bytes = snapshot.raw_row_state_json_bytes;
                    diagnostic.raw_runtime_db_page_size = snapshot.raw_runtime_db_page_size;
                    diagnostic.raw_runtime_db_page_count = snapshot.raw_runtime_db_page_count;
                    diagnostic.raw_runtime_db_freelist_count =
                        snapshot.raw_runtime_db_freelist_count;
                    diagnostic.raw_runtime_db_journal_mode = snapshot.raw_runtime_db_journal_mode;
                    diagnostic.raw_runtime_db_locking_mode = snapshot.raw_runtime_db_locking_mode;
                    diagnostic.raw_probe_open_db_elapsed_ms = snapshot.raw_probe_open_db_elapsed_ms;
                    diagnostic.raw_probe_check_table_exists_elapsed_ms =
                        snapshot.raw_probe_check_table_exists_elapsed_ms;
                    diagnostic.raw_probe_meta_query_plan_elapsed_ms =
                        snapshot.raw_probe_meta_query_plan_elapsed_ms;
                    diagnostic.raw_probe_meta_query_elapsed_ms =
                        snapshot.raw_probe_meta_query_elapsed_ms;
                    diagnostic.raw_probe_size_query_plan_elapsed_ms =
                        snapshot.raw_probe_size_query_plan_elapsed_ms;
                    diagnostic.raw_probe_size_query_elapsed_ms =
                        snapshot.raw_probe_size_query_elapsed_ms;
                    diagnostic.raw_probe_runtime_db_facts_elapsed_ms =
                        snapshot.raw_probe_runtime_db_facts_elapsed_ms;
                }
                Ok(RawProbeWorkerMessage::Finished(result)) => {
                    if let Err(error) = result {
                        return Err(anyhow!(
                            "raw persisted rebuild row probe worker failed: {error}"
                        ));
                    }
                    diagnostic.raw_probe_stage = RawPersistedRebuildRowProbeStage::Complete;
                    diagnostic.raw_probe_total_elapsed_ms =
                        started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
                    diagnostic.raw_probe_skipped_stages = Vec::new();
                    let (reason_class, explanation) =
                        Self::classify_raw_persisted_rebuild_row_probe(&diagnostic);
                    diagnostic.raw_persisted_rebuild_row_reason_class = reason_class;
                    diagnostic.raw_persisted_rebuild_row_explanation = explanation;
                    return Ok(diagnostic);
                }
                Err(mpsc::RecvTimeoutError::Timeout) => {
                    diagnostic.raw_probe_budget_exhausted = true;
                    diagnostic.raw_probe_total_elapsed_ms =
                        started_at.elapsed().as_millis().min(u64::MAX as u128) as u64;
                    diagnostic.raw_probe_skipped_stages =
                        Self::raw_persisted_rebuild_row_skipped_stages(
                            diagnostic.raw_probe_stage,
                            true,
                        );
                    let (reason_class, explanation) =
                        Self::classify_raw_persisted_rebuild_row_probe(&diagnostic);
                    diagnostic.raw_persisted_rebuild_row_reason_class = reason_class;
                    diagnostic.raw_persisted_rebuild_row_explanation = explanation;
                    return Ok(diagnostic);
                }
                Err(mpsc::RecvTimeoutError::Disconnected) => {
                    return Err(anyhow!(
                        "raw persisted rebuild row probe worker disconnected before returning a result"
                    ));
                }
            }
        }
    }

