    fn probe_persisted_rebuild_row_step_meta_full_orchestration_diff_read_only_with_options(
        runtime_db_path: &Path,
        options: StepMetaFullOrchestrationDiffProbeOptions,
    ) -> Result<PersistedRebuildRowStepMetaFullOrchestrationDiffDiagnostic> {
        let started_at = Instant::now();
        let deadline = started_at + StdDuration::from_millis(options.budget_ms);

        let remaining_for_isolated = deadline.saturating_duration_since(Instant::now());
        let isolated = if remaining_for_isolated.is_zero() {
            StorageStepMetaIsolatedSharedDiagnostic {
                stage: copybot_storage::DiscoveryPersistedRebuildRowStepMetaIsolatedSharedStage::SharedPath,
                budget_exhausted: true,
                total_elapsed_ms: 0,
                prepare_exists_elapsed_ms: None,
                step_exists_elapsed_ms: None,
                prepare_meta_elapsed_ms: None,
                step_meta_elapsed_ms: None,
                extract_phase_elapsed_ms: None,
                extract_updated_at_elapsed_ms: None,
                row_exists: None,
                row_phase: None,
                row_updated_at: None,
                loads_connection_facts_before_meta_query: true,
                uses_query_plus_next: true,
                finalizes_exists_before_prepare_meta: true,
                extracts_phase_and_updated_at_after_step: true,
                measures_prepare_meta_separately: true,
                measures_extract_separately: true,
            }
        } else {
            SqliteStore::probe_discovery_persisted_rebuild_row_step_meta_isolated_shared_read_only(
                runtime_db_path,
                &StorageStepMetaIsolatedSharedOptions {
                    budget_ms: remaining_for_isolated.as_millis().min(u64::MAX as u128) as u64,
                    test_force_shared_step_meta_delay_ms: options
                        .test_force_isolated_shared_step_meta_delay_ms,
                },
            )?
        };

        let remaining_for_full_current = deadline.saturating_duration_since(Instant::now());
        let full_current =
            SqliteStore::probe_discovery_persisted_rebuild_row_step_meta_compare_read_only(
                runtime_db_path,
                &StorageStepMetaCompareOptions {
                    budget_ms: remaining_for_full_current.as_millis().min(u64::MAX as u128) as u64,
                    test_force_shared_step_meta_delay_ms: options
                        .test_force_full_current_shared_step_meta_delay_ms,
                    ..StorageStepMetaCompareOptions::default()
                },
            )?;

        let remaining_for_truncated = deadline.saturating_duration_since(Instant::now());
        let full_truncated =
            SqliteStore::probe_discovery_persisted_rebuild_row_step_meta_compare_read_only(
                runtime_db_path,
                &StorageStepMetaCompareOptions {
                    budget_ms: remaining_for_truncated.as_millis().min(u64::MAX as u128) as u64,
                    test_force_shared_step_meta_delay_ms: options
                        .test_force_full_truncated_shared_step_meta_delay_ms,
                    test_truncate_after_shared_section: true,
                    ..StorageStepMetaCompareOptions::default()
                },
            )?;

        let remaining_for_no_snapshot = deadline.saturating_duration_since(Instant::now());
        let full_no_snapshot =
            SqliteStore::probe_discovery_persisted_rebuild_row_step_meta_compare_read_only(
                runtime_db_path,
                &StorageStepMetaCompareOptions {
                    budget_ms: remaining_for_no_snapshot.as_millis().min(u64::MAX as u128) as u64,
                    test_force_shared_step_meta_delay_ms: options
                        .test_force_full_no_snapshot_shared_step_meta_delay_ms,
                    test_disable_progress_snapshots: true,
                    ..StorageStepMetaCompareOptions::default()
                },
            )?;

        let mut mapped = PersistedRebuildRowStepMetaFullOrchestrationDiffDiagnostic {
            step_meta_full_orchestration_diff_stage: if isolated.budget_exhausted {
                PersistedRebuildRowStepMetaFullOrchestrationDiffStage::IsolatedSharedHelper
            } else if full_current.budget_exhausted {
                PersistedRebuildRowStepMetaFullOrchestrationDiffStage::FullCurrentStepMetaDetailMode
            } else if full_truncated.budget_exhausted {
                PersistedRebuildRowStepMetaFullOrchestrationDiffStage::FullTruncatedAfterShared
            } else if full_no_snapshot.budget_exhausted {
                PersistedRebuildRowStepMetaFullOrchestrationDiffStage::FullNoSnapshotMode
            } else {
                PersistedRebuildRowStepMetaFullOrchestrationDiffStage::Complete
            },
            step_meta_full_orchestration_diff_budget_exhausted: isolated.budget_exhausted
                || full_current.budget_exhausted
                || full_truncated.budget_exhausted
                || full_no_snapshot.budget_exhausted,
            step_meta_full_orchestration_diff_total_elapsed_ms: started_at
                .elapsed()
                .as_millis()
                .min(u64::MAX as u128) as u64,
            step_meta_full_orchestration_diff_isolated_shared_step_meta_elapsed_ms: isolated
                .step_meta_elapsed_ms,
            step_meta_full_orchestration_diff_isolated_shared_row_exists: isolated.row_exists,
            step_meta_full_orchestration_diff_full_current_prepare_exists_elapsed_ms: full_current
                .shared_prepare_exists_elapsed_ms,
            step_meta_full_orchestration_diff_full_current_step_exists_elapsed_ms: full_current
                .shared_step_exists_elapsed_ms,
            step_meta_full_orchestration_diff_full_current_prepare_meta_elapsed_ms: full_current
                .shared_prepare_meta_elapsed_ms,
            step_meta_full_orchestration_diff_full_current_step_meta_elapsed_ms: full_current
                .shared_step_meta_elapsed_ms,
            step_meta_full_orchestration_diff_full_current_extract_phase_elapsed_ms: full_current
                .shared_extract_phase_elapsed_ms,
            step_meta_full_orchestration_diff_full_current_extract_updated_at_elapsed_ms:
                full_current.shared_extract_updated_at_elapsed_ms,
            step_meta_full_orchestration_diff_full_current_row_exists: full_current
                .shared_row_exists,
            step_meta_full_orchestration_diff_full_current_ran_later_variants:
                Self::storage_step_meta_compare_ran_later_variants(&full_current),
            step_meta_full_orchestration_diff_full_current_emitted_progress_snapshots:
                full_current.progress_snapshots_emitted,
            step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_exists_elapsed_ms:
                full_truncated.shared_prepare_exists_elapsed_ms,
            step_meta_full_orchestration_diff_full_truncated_after_shared_step_exists_elapsed_ms:
                full_truncated.shared_step_exists_elapsed_ms,
            step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_meta_elapsed_ms:
                full_truncated.shared_prepare_meta_elapsed_ms,
            step_meta_full_orchestration_diff_full_truncated_after_shared_step_meta_elapsed_ms:
                full_truncated.shared_step_meta_elapsed_ms,
            step_meta_full_orchestration_diff_full_truncated_after_shared_extract_phase_elapsed_ms:
                full_truncated.shared_extract_phase_elapsed_ms,
            step_meta_full_orchestration_diff_full_truncated_after_shared_extract_updated_at_elapsed_ms:
                full_truncated.shared_extract_updated_at_elapsed_ms,
            step_meta_full_orchestration_diff_full_truncated_after_shared_row_exists:
                full_truncated.shared_row_exists,
            step_meta_full_orchestration_diff_full_truncated_ran_later_variants:
                Self::storage_step_meta_compare_ran_later_variants(&full_truncated),
            step_meta_full_orchestration_diff_full_no_snapshot_step_meta_elapsed_ms:
                full_no_snapshot.shared_step_meta_elapsed_ms,
            step_meta_full_orchestration_diff_full_no_snapshot_row_exists:
                full_no_snapshot.shared_row_exists,
            step_meta_full_orchestration_diff_full_no_snapshot_ran_later_variants:
                Self::storage_step_meta_compare_ran_later_variants(&full_no_snapshot),
            step_meta_full_orchestration_diff_full_no_snapshot_emitted_progress_snapshots:
                full_no_snapshot.progress_snapshots_emitted,
            step_meta_full_orchestration_diff_reason_class:
                PersistedRebuildRowStepMetaFullOrchestrationDiffReasonClass::StepMetaFullOrchestrationDiffUnprovenDueToBudgetExhausted,
            step_meta_full_orchestration_diff_explanation:
                "step-meta full-orchestration diff has not been classified yet".to_string(),
        };
        let (reason_class, explanation) =
            Self::classify_persisted_rebuild_row_step_meta_full_orchestration_diff(&mapped);
        mapped.step_meta_full_orchestration_diff_reason_class = reason_class;
        mapped.step_meta_full_orchestration_diff_explanation = explanation;
        Ok(mapped)
    }

    pub fn capture_persisted_rebuild_row_slow_event_read_only(
        runtime_db_path: &Path,
        threshold_ms: u64,
        budget_ms: u64,
    ) -> Result<PersistedRebuildRowSlowEventCaptureDiagnostic> {
        Self::capture_persisted_rebuild_row_slow_event_read_only_with_options(
            runtime_db_path,
            SlowEventCaptureProbeOptions {
                budget_ms,
                threshold_ms,
                ..SlowEventCaptureProbeOptions::default()
            },
        )
    }

    fn capture_persisted_rebuild_row_slow_event_read_only_with_options(
        runtime_db_path: &Path,
        options: SlowEventCaptureProbeOptions,
    ) -> Result<PersistedRebuildRowSlowEventCaptureDiagnostic> {
        #[derive(Clone, Copy)]
        struct SlowStageCandidate {
            stage: &'static str,
            elapsed_ms: Option<u64>,
            path_identity: &'static str,
            previous_stage: Option<&'static str>,
            previous_elapsed_ms: Option<u64>,
            next_stage: Option<&'static str>,
            next_elapsed_ms: Option<u64>,
        }

        let invocation_ordinal =
            Self::next_persisted_rebuild_row_slow_event_capture_invocation_ordinal();
        let orchestration = match Self::probe_persisted_rebuild_row_step_meta_full_orchestration_diff_read_only_with_options(
            runtime_db_path,
            StepMetaFullOrchestrationDiffProbeOptions {
                budget_ms: options.budget_ms,
                test_force_isolated_shared_step_meta_delay_ms: options
                    .test_force_isolated_shared_step_meta_delay_ms,
                test_force_full_current_shared_step_meta_delay_ms: options
                    .test_force_full_current_shared_step_meta_delay_ms,
                test_force_full_truncated_shared_step_meta_delay_ms: options
                    .test_force_full_truncated_shared_step_meta_delay_ms,
                test_force_full_no_snapshot_shared_step_meta_delay_ms: options
                    .test_force_full_no_snapshot_shared_step_meta_delay_ms,
            },
        ) {
            Ok(value) => Some(value),
            Err(error)
                if error
                    .to_string()
                    .contains("no such table: discovery_persisted_rebuild_state") =>
            {
                None
            }
            Err(error) => return Err(error),
        };

        let connection_facts = SqliteStore::open_read_only(runtime_db_path)
            .with_context(|| {
                format!(
                    "failed opening sqlite db read-only for slow-event capture {}",
                    runtime_db_path.display()
                )
            })?
            .sqlite_read_only_driver_compare_facts()
            .context("failed reading sqlite slow-event capture connection facts")?;
        let (runtime_db_size_bytes, runtime_db_mtime, wal_present, wal_size_bytes) =
            Self::persisted_rebuild_row_slow_event_db_metadata(runtime_db_path);

        if orchestration.is_none() {
            return Ok(PersistedRebuildRowSlowEventCaptureDiagnostic {
                slow_event_capture_observed: false,
                slow_event_capture_budget_exhausted: false,
                slow_event_capture_stage: None,
                slow_event_capture_elapsed_ms: None,
                slow_event_capture_threshold_ms: options.threshold_ms,
                slow_event_capture_process_id: std::process::id(),
                slow_event_capture_process_uptime_ms: None,
                slow_event_capture_first_relevant_invocation_in_process: Some(
                    invocation_ordinal == 1,
                ),
                slow_event_capture_runtime_db_path: runtime_db_path.display().to_string(),
                slow_event_capture_runtime_db_size_bytes: runtime_db_size_bytes,
                slow_event_capture_runtime_db_mtime: runtime_db_mtime,
                slow_event_capture_wal_present: wal_present,
                slow_event_capture_wal_size_bytes: wal_size_bytes,
                slow_event_capture_busy_timeout_ms: Some(connection_facts.busy_timeout_ms),
                slow_event_capture_cache_size: Some(connection_facts.cache_size),
                slow_event_capture_mmap_size: Some(connection_facts.mmap_size),
                slow_event_capture_query_only: Some(connection_facts.query_only),
                slow_event_capture_journal_mode: Some(connection_facts.journal_mode),
                slow_event_capture_locking_mode: Some(connection_facts.locking_mode),
                slow_event_capture_surface_identity:
                    "probe_persisted_rebuild_row_step_meta_full_orchestration_diff_read_only"
                        .to_string(),
                slow_event_capture_path_identity: Some("persisted_rebuild_row_missing".to_string()),
                slow_event_capture_previous_stage: None,
                slow_event_capture_previous_elapsed_ms: None,
                slow_event_capture_next_stage: None,
                slow_event_capture_next_elapsed_ms: None,
                slow_event_capture_reason_class:
                    PersistedRebuildRowSlowEventCaptureReasonClass::SlowEventRowMissing,
                slow_event_capture_explanation:
                    "the accepted full-orchestration probe could not find discovery_persisted_rebuild_state on the runtime db, so the persisted rebuild row is missing for this capture".to_string(),
            });
        }

        let orchestration = orchestration.expect("checked above");

        let row_missing = orchestration
            .step_meta_full_orchestration_diff_isolated_shared_row_exists
            == Some(false)
            || orchestration.step_meta_full_orchestration_diff_full_current_row_exists
                == Some(false)
            || orchestration
                .step_meta_full_orchestration_diff_full_truncated_after_shared_row_exists
                == Some(false)
            || orchestration.step_meta_full_orchestration_diff_full_no_snapshot_row_exists
                == Some(false);

        let candidates = [
            SlowStageCandidate {
                stage: "isolated_shared_step_meta",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_isolated_shared_step_meta_elapsed_ms,
                path_identity: "isolated_shared_helper",
                previous_stage: None,
                previous_elapsed_ms: None,
                next_stage: None,
                next_elapsed_ms: None,
            },
            SlowStageCandidate {
                stage: "full_current_prepare_exists",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_prepare_exists_elapsed_ms,
                path_identity: "full_current_shared_branch",
                previous_stage: None,
                previous_elapsed_ms: None,
                next_stage: Some("full_current_step_exists"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_step_exists_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_current_step_exists",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_step_exists_elapsed_ms,
                path_identity: "full_current_shared_branch",
                previous_stage: Some("full_current_prepare_exists"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_prepare_exists_elapsed_ms,
                next_stage: Some("full_current_prepare_meta"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_prepare_meta_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_current_prepare_meta",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_prepare_meta_elapsed_ms,
                path_identity: "full_current_shared_branch",
                previous_stage: Some("full_current_step_exists"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_step_exists_elapsed_ms,
                next_stage: Some("full_current_step_meta"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_step_meta_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_current_step_meta",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_step_meta_elapsed_ms,
                path_identity: "full_current_shared_branch",
                previous_stage: Some("full_current_prepare_meta"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_prepare_meta_elapsed_ms,
                next_stage: Some("full_current_extract_phase"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_extract_phase_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_current_extract_phase",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_extract_phase_elapsed_ms,
                path_identity: "full_current_shared_branch",
                previous_stage: Some("full_current_step_meta"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_step_meta_elapsed_ms,
                next_stage: Some("full_current_extract_updated_at"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_extract_updated_at_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_current_extract_updated_at",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_extract_updated_at_elapsed_ms,
                path_identity: "full_current_shared_branch",
                previous_stage: Some("full_current_extract_phase"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_current_extract_phase_elapsed_ms,
                next_stage: None,
                next_elapsed_ms: None,
            },
            SlowStageCandidate {
                stage: "full_truncated_after_shared_prepare_exists",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_exists_elapsed_ms,
                path_identity: "full_truncated_after_shared_branch",
                previous_stage: None,
                previous_elapsed_ms: None,
                next_stage: Some("full_truncated_after_shared_step_exists"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_step_exists_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_truncated_after_shared_step_exists",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_step_exists_elapsed_ms,
                path_identity: "full_truncated_after_shared_branch",
                previous_stage: Some("full_truncated_after_shared_prepare_exists"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_exists_elapsed_ms,
                next_stage: Some("full_truncated_after_shared_prepare_meta"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_meta_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_truncated_after_shared_prepare_meta",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_meta_elapsed_ms,
                path_identity: "full_truncated_after_shared_branch",
                previous_stage: Some("full_truncated_after_shared_step_exists"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_step_exists_elapsed_ms,
                next_stage: Some("full_truncated_after_shared_step_meta"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_step_meta_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_truncated_after_shared_step_meta",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_step_meta_elapsed_ms,
                path_identity: "full_truncated_after_shared_branch",
                previous_stage: Some("full_truncated_after_shared_prepare_meta"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_prepare_meta_elapsed_ms,
                next_stage: Some("full_truncated_after_shared_extract_phase"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_extract_phase_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_truncated_after_shared_extract_phase",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_extract_phase_elapsed_ms,
                path_identity: "full_truncated_after_shared_branch",
                previous_stage: Some("full_truncated_after_shared_step_meta"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_step_meta_elapsed_ms,
                next_stage: Some("full_truncated_after_shared_extract_updated_at"),
                next_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_extract_updated_at_elapsed_ms,
            },
            SlowStageCandidate {
                stage: "full_truncated_after_shared_extract_updated_at",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_extract_updated_at_elapsed_ms,
                path_identity: "full_truncated_after_shared_branch",
                previous_stage: Some("full_truncated_after_shared_extract_phase"),
                previous_elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_truncated_after_shared_extract_phase_elapsed_ms,
                next_stage: None,
                next_elapsed_ms: None,
            },
            SlowStageCandidate {
                stage: "full_no_snapshot_step_meta",
                elapsed_ms: orchestration
                    .step_meta_full_orchestration_diff_full_no_snapshot_step_meta_elapsed_ms,
                path_identity: "full_no_snapshot_branch",
                previous_stage: None,
                previous_elapsed_ms: None,
                next_stage: None,
                next_elapsed_ms: None,
            },
        ];
        let observed_stage = candidates
            .into_iter()
            .filter_map(|candidate| {
                candidate
                    .elapsed_ms
                    .filter(|elapsed_ms| *elapsed_ms >= options.threshold_ms)
                    .map(|elapsed_ms| (candidate, elapsed_ms))
            })
            .max_by_key(|(_, elapsed_ms)| *elapsed_ms);

        let (
            reason_class,
            explanation,
            observed,
            stage,
            elapsed_ms,
            path_identity,
            previous_stage,
            previous_elapsed_ms,
            next_stage,
            next_elapsed_ms,
        ) = if row_missing {
            (
                    PersistedRebuildRowSlowEventCaptureReasonClass::SlowEventRowMissing,
                    "the accepted full-orchestration probe proved that discovery_persisted_rebuild_state(id=1) is missing on the runtime db".to_string(),
                    false,
                    None,
                    None,
                    Some("persisted_rebuild_row_missing".to_string()),
                    None,
                    None,
                    None,
                    None,
                )
        } else if let Some((candidate, elapsed_ms)) = observed_stage {
            let reason_class = if candidate.stage.contains("step_meta") {
                PersistedRebuildRowSlowEventCaptureReasonClass::SlowEventObservedOnSharedStepMeta
            } else {
                PersistedRebuildRowSlowEventCaptureReasonClass::SlowEventObservedOnOtherStage
            };
            (
                    reason_class,
                    format!(
                        "the accepted full-orchestration probe observed a real slow event on stage {} within path {} (elapsed_ms={}, threshold_ms={}, surface_identity=probe_persisted_rebuild_row_step_meta_full_orchestration_diff_read_only)",
                        candidate.stage,
                        candidate.path_identity,
                        elapsed_ms,
                        options.threshold_ms
                    ),
                    true,
                    Some(candidate.stage.to_string()),
                    Some(elapsed_ms),
                    Some(candidate.path_identity.to_string()),
                    candidate.previous_stage.map(str::to_string),
                    candidate.previous_elapsed_ms,
                    candidate.next_stage.map(str::to_string),
                    candidate.next_elapsed_ms,
                )
        } else if orchestration.step_meta_full_orchestration_diff_budget_exhausted {
            (
                    PersistedRebuildRowSlowEventCaptureReasonClass::SlowEventCaptureUnprovenDueToBudgetExhausted,
                    format!(
                        "the accepted full-orchestration probe exhausted its diagnostic budget while in stage {} before any threshold-exceeding slow event was captured (threshold_ms={})",
                        serde_json::to_string(
                            &orchestration.step_meta_full_orchestration_diff_stage
                        )
                        .unwrap_or_else(|_| "\"unknown\"".to_string())
                        .trim_matches('"'),
                        options.threshold_ms
                    ),
                    false,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                )
        } else {
            let max_candidate = candidates
                .into_iter()
                .filter_map(|candidate| {
                    candidate
                        .elapsed_ms
                        .map(|elapsed_ms| (candidate.stage, elapsed_ms))
                })
                .max_by_key(|(_, elapsed_ms)| *elapsed_ms);
            let max_stage = max_candidate.map(|(stage, _)| stage).unwrap_or("none");
            let max_elapsed = max_candidate.map(|(_, elapsed_ms)| elapsed_ms).unwrap_or(0);
            (
                    PersistedRebuildRowSlowEventCaptureReasonClass::SlowEventNotObserved,
                    format!(
                        "the accepted full-orchestration probe completed without observing any stage at or above the configured slow-event threshold (threshold_ms={}, max_stage={}, max_elapsed_ms={})",
                        options.threshold_ms,
                        max_stage,
                        max_elapsed
                    ),
                    false,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                    None,
                )
        };

        Ok(PersistedRebuildRowSlowEventCaptureDiagnostic {
            slow_event_capture_observed: observed,
            slow_event_capture_budget_exhausted: orchestration
                .step_meta_full_orchestration_diff_budget_exhausted,
            slow_event_capture_stage: stage,
            slow_event_capture_elapsed_ms: elapsed_ms,
            slow_event_capture_threshold_ms: options.threshold_ms,
            slow_event_capture_process_id: std::process::id(),
            slow_event_capture_process_uptime_ms: None,
            slow_event_capture_first_relevant_invocation_in_process: Some(invocation_ordinal == 1),
            slow_event_capture_runtime_db_path: runtime_db_path.display().to_string(),
            slow_event_capture_runtime_db_size_bytes: runtime_db_size_bytes,
            slow_event_capture_runtime_db_mtime: runtime_db_mtime,
            slow_event_capture_wal_present: wal_present,
            slow_event_capture_wal_size_bytes: wal_size_bytes,
            slow_event_capture_busy_timeout_ms: Some(connection_facts.busy_timeout_ms),
            slow_event_capture_cache_size: Some(connection_facts.cache_size),
            slow_event_capture_mmap_size: Some(connection_facts.mmap_size),
            slow_event_capture_query_only: Some(connection_facts.query_only),
            slow_event_capture_journal_mode: Some(connection_facts.journal_mode),
            slow_event_capture_locking_mode: Some(connection_facts.locking_mode),
            slow_event_capture_surface_identity:
                "probe_persisted_rebuild_row_step_meta_full_orchestration_diff_read_only"
                    .to_string(),
            slow_event_capture_path_identity: path_identity,
            slow_event_capture_previous_stage: previous_stage,
            slow_event_capture_previous_elapsed_ms: previous_elapsed_ms,
            slow_event_capture_next_stage: next_stage,
            slow_event_capture_next_elapsed_ms: next_elapsed_ms,
            slow_event_capture_reason_class: reason_class,
            slow_event_capture_explanation: explanation,
        })
    }

    pub fn probe_persisted_rebuild_row_shared_ordering_diff_read_only(
        runtime_db_path: &Path,
        budget_ms: u64,
    ) -> Result<PersistedRebuildRowSharedOrderingDiffDiagnostic> {
        Self::probe_persisted_rebuild_row_shared_ordering_diff_read_only_with_options(
            runtime_db_path,
            SharedOrderingDiffProbeOptions {
                budget_ms,
                ..SharedOrderingDiffProbeOptions::default()
            },
        )
    }

    fn probe_persisted_rebuild_row_shared_ordering_diff_read_only_with_options(
        runtime_db_path: &Path,
        options: SharedOrderingDiffProbeOptions,
    ) -> Result<PersistedRebuildRowSharedOrderingDiffDiagnostic> {
        #[derive(Debug)]
        struct SharedOrderingBranchSequenceResult {
            execution_order: Vec<String>,
            isolated: StorageStepMetaIsolatedSharedDiagnostic,
            full: PersistedRebuildRowStepMetaCompareDiagnostic,
        }

        let started_at = Instant::now();
        let deadline = started_at + StdDuration::from_millis(options.budget_ms);
        let run_isolated = |budget_ms: u64, delay_ms: Option<u64>| {
            SqliteStore::probe_discovery_persisted_rebuild_row_step_meta_isolated_shared_read_only(
                runtime_db_path,
                &StorageStepMetaIsolatedSharedOptions {
                    budget_ms,
                    test_force_shared_step_meta_delay_ms: delay_ms,
                },
            )
        };
        let run_full = |budget_ms: u64, delay_ms: Option<u64>| {
            Self::probe_persisted_rebuild_row_step_meta_compare_read_only_with_options(
                runtime_db_path,
                StorageStepMetaCompareOptions {
                    budget_ms,
                    test_force_shared_step_meta_delay_ms: delay_ms,
                    ..StorageStepMetaCompareOptions::default()
                },
            )
        };
        let remaining_budget_ms = |deadline: Instant| {
            deadline
                .saturating_duration_since(Instant::now())
                .as_millis()
                .min(u64::MAX as u128) as u64
        };
        let run_branch = |first_isolated: bool,
                          first_delay_ms: Option<u64>,
                          second_delay_ms: Option<u64>|
         -> Result<SharedOrderingBranchSequenceResult> {
            let branch_deadline =
                Instant::now() + StdDuration::from_millis(remaining_budget_ms(deadline));
            let mut execution_order = Vec::with_capacity(2);
            let (isolated, full) = if first_isolated {
                execution_order.push("isolated_shared_helper".to_string());
                let isolated = run_isolated(remaining_budget_ms(branch_deadline), first_delay_ms)?;
                execution_order.push("full_current_branch".to_string());
                let full = run_full(remaining_budget_ms(branch_deadline), second_delay_ms)?;
                (isolated, full)
            } else {
                execution_order.push("full_current_branch".to_string());
                let full = run_full(remaining_budget_ms(branch_deadline), first_delay_ms)?;
                execution_order.push("isolated_shared_helper".to_string());
                let isolated = run_isolated(remaining_budget_ms(branch_deadline), second_delay_ms)?;
                (isolated, full)
            };
            Ok(SharedOrderingBranchSequenceResult {
                execution_order,
                isolated,
                full,
            })
        };

        let isolated_first_branch = run_branch(
            true,
            options.test_force_isolated_first_delay_ms,
            options.test_force_full_second_delay_ms,
        )?;
        let full_first_branch = run_branch(
            false,
            options.test_force_full_first_delay_ms,
            options.test_force_isolated_second_delay_ms,
        )?;

        let isolated_repeat = run_isolated(
            remaining_budget_ms(deadline),
            options.test_force_isolated_repeat_delay_ms,
        )?;
        let full_repeat = run_full(
            remaining_budget_ms(deadline),
            options.test_force_full_repeat_delay_ms,
        )?;

        let mut mapped = PersistedRebuildRowSharedOrderingDiffDiagnostic {
            shared_ordering_diff_stage: if isolated_first_branch.isolated.budget_exhausted
                || isolated_first_branch.full.step_meta_compare_budget_exhausted
            {
                PersistedRebuildRowSharedOrderingDiffStage::IsolatedFirstThenFullSecond
            } else if full_first_branch.full.step_meta_compare_budget_exhausted
                || full_first_branch.isolated.budget_exhausted
            {
                PersistedRebuildRowSharedOrderingDiffStage::FullFirstThenIsolatedSecond
            } else if isolated_repeat.budget_exhausted || full_repeat.step_meta_compare_budget_exhausted
            {
                PersistedRebuildRowSharedOrderingDiffStage::RepeatBranches
            } else {
                PersistedRebuildRowSharedOrderingDiffStage::Complete
            },
            shared_ordering_diff_budget_exhausted: isolated_first_branch.isolated.budget_exhausted
                || isolated_first_branch.full.step_meta_compare_budget_exhausted
                || full_first_branch.full.step_meta_compare_budget_exhausted
                || full_first_branch.isolated.budget_exhausted
                || isolated_repeat.budget_exhausted
                || full_repeat.step_meta_compare_budget_exhausted,
            shared_ordering_diff_total_elapsed_ms: started_at
                .elapsed()
                .as_millis()
                .min(u64::MAX as u128) as u64,
            shared_ordering_diff_mode_level_independent_orderings: false,
            shared_ordering_diff_isolated_first_branch_execution_order:
                isolated_first_branch.execution_order,
            shared_ordering_diff_isolated_first_step_meta_elapsed_ms: isolated_first_branch
                .isolated
                .step_meta_elapsed_ms,
            shared_ordering_diff_isolated_first_row_exists: isolated_first_branch
                .isolated
                .row_exists,
            shared_ordering_diff_full_second_step_meta_elapsed_ms: isolated_first_branch
                .full
                .step_meta_shared_connection_step_meta_elapsed_ms,
            shared_ordering_diff_full_second_row_exists: isolated_first_branch
                .full
                .step_meta_shared_connection_row_exists,
            shared_ordering_diff_full_second_ran_later_variants:
                Self::step_meta_full_mode_ran_later_variants(&isolated_first_branch.full),
            shared_ordering_diff_full_first_branch_execution_order:
                full_first_branch.execution_order,
            shared_ordering_diff_full_first_step_meta_elapsed_ms: full_first_branch
                .full
                .step_meta_shared_connection_step_meta_elapsed_ms,
            shared_ordering_diff_full_first_row_exists: full_first_branch
                .full
                .step_meta_shared_connection_row_exists,
            shared_ordering_diff_full_first_ran_later_variants:
                Self::step_meta_full_mode_ran_later_variants(&full_first_branch.full),
            shared_ordering_diff_isolated_second_step_meta_elapsed_ms: full_first_branch
                .isolated
                .step_meta_elapsed_ms,
            shared_ordering_diff_isolated_second_row_exists: full_first_branch
                .isolated
                .row_exists,
            shared_ordering_diff_isolated_repeat_step_meta_elapsed_ms: isolated_repeat
                .step_meta_elapsed_ms,
            shared_ordering_diff_isolated_repeat_row_exists: isolated_repeat.row_exists,
            shared_ordering_diff_full_repeat_step_meta_elapsed_ms: full_repeat
                .step_meta_shared_connection_step_meta_elapsed_ms,
            shared_ordering_diff_full_repeat_row_exists: full_repeat
                .step_meta_shared_connection_row_exists,
            shared_ordering_diff_full_repeat_ran_later_variants:
                Self::step_meta_full_mode_ran_later_variants(&full_repeat),
            shared_ordering_diff_reason_class:
                PersistedRebuildRowSharedOrderingDiffReasonClass::SharedOrderingDiffUnprovenDueToBudgetExhausted,
            shared_ordering_diff_explanation:
                "shared-ordering diff has not been classified yet".to_string(),
        };
        let (reason_class, explanation) =
            Self::classify_persisted_rebuild_row_shared_ordering_diff(&mapped);
        mapped.shared_ordering_diff_reason_class = reason_class;
        mapped.shared_ordering_diff_explanation = explanation;
        Ok(mapped)
    }

    fn scan_replay_sol_leg_source_ahead_from_state(
        source_store: &SqliteStore,
        state: &PersistedStreamRebuildState,
    ) -> Result<ReplaySolLegSourceAheadSummary> {
        let target_buy_mints = if Self::state_uses_exact_target_filtered_sol_leg_replay(state) {
            state.payload.discovery_critical_target_buy_mints.clone()
        } else {
            Vec::new()
        };
        let target_buy_mint_filter_active = !target_buy_mints.is_empty();
        let page_limit = REPLAY_CHECKPOINT_DIAGNOSE_SOURCE_SCAN_PAGE_LIMIT.max(1);
        let runtime_cursor = source_store.load_discovery_runtime_cursor_read_only()?;
        let mut cursor = state.phase_cursor.clone();
        let mut pages_scanned = 0usize;
        let mut rows_ahead_count = 0usize;
        let mut first_cursor = None;
        let mut last_cursor = None;
        let mut last_access_path: Option<ObservedSolLegCursorAccessPath> = None;
        let mut time_budget_exhausted = false;

        loop {
            let deadline = Instant::now()
                + StdDuration::from_millis(
                    Self::replay_checkpoint_diagnose_source_scan_deadline_ms(),
                );
            let mut page_last_cursor = cursor.clone();
            let page = if target_buy_mint_filter_active {
                source_store
                    .for_each_observed_sol_leg_swap_in_window_after_cursor_for_target_buy_mints_with_budget(
                        state.window_start,
                        state.horizon_end,
                        cursor.as_ref(),
                        &target_buy_mints,
                        page_limit,
                        deadline,
                        |swap| {
                            let swap_cursor = DiscoveryRuntimeCursor {
                                ts_utc: swap.ts_utc,
                                slot: swap.slot,
                                signature: swap.signature.clone(),
                            };
                            if first_cursor.is_none() {
                                first_cursor = Some(swap_cursor.clone());
                            }
                            last_cursor = Some(swap_cursor.clone());
                            page_last_cursor = Some(swap_cursor);
                            rows_ahead_count = rows_ahead_count.saturating_add(1);
                            Ok(())
                        },
                    )?
            } else {
                source_store.for_each_observed_sol_leg_swap_in_window_after_cursor_with_budget(
                    state.window_start,
                    state.horizon_end,
                    cursor.as_ref(),
                    page_limit,
                    deadline,
                    |swap| {
                        let swap_cursor = DiscoveryRuntimeCursor {
                            ts_utc: swap.ts_utc,
                            slot: swap.slot,
                            signature: swap.signature.clone(),
                        };
                        if first_cursor.is_none() {
                            first_cursor = Some(swap_cursor.clone());
                        }
                        last_cursor = Some(swap_cursor.clone());
                        page_last_cursor = Some(swap_cursor);
                        rows_ahead_count = rows_ahead_count.saturating_add(1);
                        Ok(())
                    },
                )?
            };
            last_access_path.replace(page.access_path);
            pages_scanned = pages_scanned.saturating_add(1);
            time_budget_exhausted |= page.time_budget_exhausted && page.rows_seen == 0;
            if page.rows_seen == 0 {
                break;
            }
            cursor = page_last_cursor;
            if page.rows_seen < page_limit {
                break;
            }
        }

        Ok(ReplaySolLegSourceAheadSummary {
            runtime_cursor_beyond_rebuild_horizon: runtime_cursor
                .as_ref()
                .is_some_and(|cursor| cursor.ts_utc > state.horizon_end),
            runtime_cursor,
            target_buy_mint_filter_active,
            target_buy_mint_count: target_buy_mints.len(),
            rows_exist_beyond_checkpoint: rows_ahead_count > 0,
            rows_ahead_count,
            pages_scanned,
            first_cursor,
            last_cursor,
            access_path: last_access_path,
            time_budget_exhausted,
        })
    }

    fn replay_checkpoint_diagnose_source_scan_deadline_ms() -> u64 {
        #[cfg(test)]
        if let Some(deadline_ms) =
            take_test_force_replay_checkpoint_diagnose_source_scan_deadline_ms()
        {
            return deadline_ms;
        }
        REPLAY_CHECKPOINT_DIAGNOSE_SOURCE_SCAN_PAGE_DEADLINE_MS
    }

    pub fn compare_sol_leg_source_vs_checkpoint_read_only(
        runtime_store: &SqliteStore,
        source_store: &SqliteStore,
    ) -> Result<ReplaySolLegSourceVsCheckpointDiagnostic> {
        let Some(state) = Self::load_persisted_stream_rebuild_state_read_only(runtime_store)?
        else {
            return Ok(ReplaySolLegSourceVsCheckpointDiagnostic {
                persisted_rebuild_checkpoint_exists: false,
                rebuild_phase: None,
                rebuild_replay_subphase: None,
                publishable_checkpoint_blocker: None,
                replay_incomplete: false,
                source_comparison_applicable: false,
                source_window_start: None,
                source_horizon_end: None,
                source_runtime_cursor: source_store.load_discovery_runtime_cursor_read_only()?,
                source_runtime_cursor_beyond_rebuild_horizon: None,
                source_checkpoint_cursor: None,
                source_scan_target_buy_mint_filter_active: None,
                source_scan_target_buy_mint_count: None,
                source_rows_exist_beyond_stored_replay_checkpoint: None,
                source_rows_ahead_count: None,
                source_rows_ahead_pages_scanned: None,
                source_rows_ahead_first_cursor: None,
                source_rows_ahead_last_cursor: None,
                source_scan_access_path: None,
                source_scan_time_budget_exhausted: None,
            });
        };
        let replay_subphase = Self::replay_subphase(
            state.phase,
            state.payload.replay_wallet_stats_complete,
            state.payload.replay_candidate_activity_backfill_pending,
        );
        let blocker = Self::persisted_stream_publishable_checkpoint_blocker_from_state(&state);
        let applicable = state.phase == DiscoveryPersistedRebuildPhase::Replay
            && replay_subphase == Some("sol_leg");
        let source_ahead = if applicable {
            Some(Self::scan_replay_sol_leg_source_ahead_from_state(
                source_store,
                &state,
            )?)
        } else {
            None
        };

        Ok(ReplaySolLegSourceVsCheckpointDiagnostic {
            persisted_rebuild_checkpoint_exists: true,
            rebuild_phase: Some(state.phase.as_str().to_string()),
            rebuild_replay_subphase: replay_subphase.map(str::to_string),
            publishable_checkpoint_blocker: Some(blocker.to_string()),
            replay_incomplete: state.phase == DiscoveryPersistedRebuildPhase::Replay,
            source_comparison_applicable: applicable,
            source_window_start: Some(state.window_start),
            source_horizon_end: Some(state.horizon_end),
            source_runtime_cursor: source_ahead
                .as_ref()
                .and_then(|summary| summary.runtime_cursor.clone())
                .or_else(|| {
                    source_store
                        .load_discovery_runtime_cursor_read_only()
                        .ok()
                        .flatten()
                }),
            source_runtime_cursor_beyond_rebuild_horizon: source_ahead
                .as_ref()
                .map(|summary| summary.runtime_cursor_beyond_rebuild_horizon),
            source_checkpoint_cursor: Some(state.phase_cursor.clone()).flatten(),
            source_scan_target_buy_mint_filter_active: source_ahead
                .as_ref()
                .map(|summary| summary.target_buy_mint_filter_active),
            source_scan_target_buy_mint_count: source_ahead
                .as_ref()
                .map(|summary| summary.target_buy_mint_count),
            source_rows_exist_beyond_stored_replay_checkpoint: source_ahead
                .as_ref()
                .map(|summary| summary.rows_exist_beyond_checkpoint),
            source_rows_ahead_count: source_ahead
                .as_ref()
                .map(|summary| summary.rows_ahead_count),
            source_rows_ahead_pages_scanned: source_ahead
                .as_ref()
                .map(|summary| summary.pages_scanned),
            source_rows_ahead_first_cursor: source_ahead
                .as_ref()
                .and_then(|summary| summary.first_cursor.clone()),
            source_rows_ahead_last_cursor: source_ahead
                .as_ref()
                .and_then(|summary| summary.last_cursor.clone()),
            source_scan_access_path: source_ahead
                .as_ref()
                .and_then(|summary| summary.access_path)
                .map(|path| path.as_str().to_string()),
            source_scan_time_budget_exhausted: source_ahead
                .as_ref()
                .map(|summary| summary.time_budget_exhausted),
        })
    }

    pub fn explain_replay_sol_leg_incomplete_read_only(
        runtime_store: &SqliteStore,
        source_store: &SqliteStore,
    ) -> Result<ReplaySolLegIncompleteDiagnostic> {
        let checkpoint = Self::inspect_persisted_rebuild_state_read_only(runtime_store)?;
        let source_vs_checkpoint =
            Self::compare_sol_leg_source_vs_checkpoint_read_only(runtime_store, source_store)?;
        let blocker = checkpoint.publishable_checkpoint_blocker.as_deref();

        let (reason_class, explanation) = if !checkpoint.persisted_rebuild_checkpoint_exists {
            (
                ReplaySolLegIncompleteReasonClass::MissingPersistedCheckpoint,
                "no persisted rebuild checkpoint is stored in the runtime db, so replay_sol_leg_incomplete cannot currently be explained from a persisted replay checkpoint".to_string(),
            )
        } else if blocker.is_none() {
            (
                ReplaySolLegIncompleteReasonClass::PublishableCheckpointClear,
                "persisted rebuild checkpoint exists without a publishable checkpoint blocker"
                    .to_string(),
            )
        } else if blocker != Some("replay_sol_leg_incomplete") {
            (
                ReplaySolLegIncompleteReasonClass::PublishableCheckpointNotReplaySolLegIncomplete,
                format!(
                    "persisted rebuild checkpoint is currently blocked on {} instead of replay_sol_leg_incomplete",
                    blocker.unwrap_or("unknown")
                ),
            )
        } else if checkpoint.exact_target_surface_repairable_for_resume == Some(true) {
            (
                ReplaySolLegIncompleteReasonClass::ExactTargetSurfaceAbsentRepairableForResume,
                "persisted replay checkpoint is still on replay_sol_leg_incomplete because replay candidate activity backfill is required but discovery_critical_target_buy_mints is empty even though the buffered wallet surface is still sufficient to reconstruct it".to_string(),
            )
        } else if checkpoint.exact_target_surface_exists == Some(false) {
            (
                ReplaySolLegIncompleteReasonClass::ExactTargetSurfaceAbsentWithoutRepairPath,
                "persisted replay checkpoint is still on replay_sol_leg_incomplete because discovery_critical_target_buy_mints is empty and the current persisted wallet surface no longer satisfies the resume repair contract".to_string(),
            )
        } else if source_vs_checkpoint
            .source_rows_exist_beyond_stored_replay_checkpoint
            .unwrap_or(false)
        {
            let count = source_vs_checkpoint.source_rows_ahead_count.unwrap_or(0);
            let first = source_vs_checkpoint
                .source_rows_ahead_first_cursor
                .as_ref()
                .map(|cursor| cursor.ts_utc.to_rfc3339())
                .unwrap_or_else(|| "unknown".to_string());
            let last = source_vs_checkpoint
                .source_rows_ahead_last_cursor
                .as_ref()
                .map(|cursor| cursor.ts_utc.to_rfc3339())
                .unwrap_or_else(|| "unknown".to_string());
            if source_vs_checkpoint
                .source_scan_target_buy_mint_filter_active
                .unwrap_or(false)
            {
                (
                    ReplaySolLegIncompleteReasonClass::SourceFrontierStillAheadExactTargetFiltered,
                    format!(
                        "persisted replay checkpoint already has an exact target surface, but the source still has {count} exact-target SOL-leg rows beyond the stored replay cursor within the frozen replay horizon (first={first}, last={last})"
                    ),
                )
            } else {
                (
                    ReplaySolLegIncompleteReasonClass::SourceFrontierStillAheadBroadSource,
                    format!(
                        "persisted replay checkpoint is still replaying against the broad SOL-leg source and the source still has {count} rows beyond the stored replay cursor within the frozen replay horizon (first={first}, last={last})"
                    ),
                )
            }
        } else if source_vs_checkpoint
            .source_scan_time_budget_exhausted
            .unwrap_or(false)
        {
            let pages_scanned = source_vs_checkpoint
                .source_rows_ahead_pages_scanned
                .unwrap_or(0);
            let access_path = source_vs_checkpoint
                .source_scan_access_path
                .as_deref()
                .unwrap_or("unknown");
            (
                ReplaySolLegIncompleteReasonClass::SourceFrontierUnprovenDiagnosticScanBudgetExhausted,
                format!(
                    "the replay-sol-leg diagnostic scan exhausted its time budget before it could prove either remaining source rows or a drained frontier beyond the stored replay cursor (pages_scanned={pages_scanned}, access_path={access_path})"
                ),
            )
        } else if checkpoint.replay_candidate_activity_backfill_required == Some(true) {
            (
                ReplaySolLegIncompleteReasonClass::SourceFrontierDrainedAwaitingCandidateActivityBackfillTransition,
                "persisted replay checkpoint shows no remaining SOL-leg source beyond the stored replay cursor inside the frozen replay horizon, but replay_candidate_activity_backfill_required is still true while the checkpoint has not yet transitioned into candidate activity backfill".to_string(),
            )
        } else {
            (
                ReplaySolLegIncompleteReasonClass::SourceFrontierDrainedButCheckpointStillReplaySolLegIncomplete,
                "persisted replay checkpoint still reports replay_sol_leg_incomplete even though the diagnostic source scan found no remaining SOL-leg rows beyond the stored replay cursor and no exact-target-surface repairable gap was detected".to_string(),
            )
        };

        Ok(ReplaySolLegIncompleteDiagnostic {
            persisted_rebuild_checkpoint_exists: checkpoint.persisted_rebuild_checkpoint_exists,
            rebuild_phase: checkpoint.rebuild_phase.clone(),
            rebuild_replay_subphase: checkpoint.rebuild_replay_subphase.clone(),
            publishable_checkpoint_blocker: checkpoint.publishable_checkpoint_blocker.clone(),
            replay_incomplete: checkpoint.replay_incomplete,
            replay_sol_leg_incomplete_reason_class: reason_class,
            replay_sol_leg_incomplete_explanation: explanation,
            checkpoint,
            source_vs_checkpoint,
        })
    }

    fn state_can_carry_forward_replay_sol_leg_reentry(
        &self,
        state: &PersistedStreamRebuildState,
    ) -> bool {
        if self.config.min_buy_count == 0 {
            return false;
        }
        Self::state_has_replay_wallet_stats_milestone(state)
    }

    fn state_has_replay_wallet_stats_milestone(state: &PersistedStreamRebuildState) -> bool {
        state.payload.replay_wallet_stats_milestone_reached
            || match state.phase {
                DiscoveryPersistedRebuildPhase::Replay => {
                    state.payload.replay_wallet_stats_complete
                        || state.payload.replay_candidate_activity_backfill_required
                        || state.payload.replay_candidate_activity_backfill_pending
                }
                DiscoveryPersistedRebuildPhase::PublishPending => true,
                _ => false,
            }
    }

    pub fn new(config: DiscoveryConfig, shadow_quality: ShadowConfig) -> Self {
        Self::new_with_helius(config, shadow_quality, None)
    }

    pub fn new_with_helius(
        config: DiscoveryConfig,
        shadow_quality: ShadowConfig,
        helius_http_url: Option<String>,
    ) -> Self {
        let helius_http_url = helius_http_url
            .map(|url| url.trim().to_string())
            .filter(|url| !url.is_empty() && !url.contains("REPLACE_ME"));
        Self {
            config,
            shadow_quality,
            helius_http_url,
            window_state: Arc::new(Mutex::new(DiscoveryWindowState::default())),
        }
    }

    pub fn selector_proof_report(
        &self,
        store: &SqliteStore,
        request: &DiscoverySelectorProofRequest,
    ) -> Result<DiscoverySelectorProofReport> {
        let db_metadata = fs::metadata(&request.db_path)
            .with_context(|| format!("failed reading db metadata {}", request.db_path.display()))?;
        let db_file_mtime_utc = db_metadata
            .modified()
            .map(DateTime::<Utc>::from)
            .with_context(|| {
                format!(
                    "failed reading db modified time {}",
                    request.db_path.display()
                )
            })?;
        let db_facts = store.sqlite_read_only_probe_facts().with_context(|| {
            format!(
                "failed probing sqlite read-only facts {}",
                request.db_path.display()
            )
        })?;
        let metrics_window_start = self.metrics_window_start(request.fixed_now_utc);
        let selector_state = self.build_wallet_snapshots_from_persisted_stream_one_shot_state(
            store,
            metrics_window_start,
            request.fixed_now_utc,
        )?;
        let ranked = rank_follow_candidates(&selector_state.snapshots, self.config.min_score);
        let ranked_wallets = desired_wallets(&ranked, self.config.follow_top_n);
        let reject_breakdown = self.selector_proof_reject_breakdown(
            &selector_state.outcomes,
            &selector_state.by_wallet,
            &selector_state.token_quality_resolutions,
        );
        let seen_wallet_ids: Vec<String> = selector_state
            .snapshots
            .iter()
            .map(|snapshot| snapshot.wallet_id.clone())
            .collect();
        let wallet_activity_coverage = self.selector_proof_wallet_activity_coverage(
            store,
            &seen_wallet_ids,
            metrics_window_start,
        )?;
        let rejected_wallet_samples =
            self.selector_proof_rejected_wallet_samples(&selector_state.outcomes);
        let selector_universe_explanation = self
            .selector_proof_universe_explanation(
                selector_state.observed_swaps_loaded as u64,
                selector_state.snapshots.len() as u64,
                ranked.len() as u64,
            )
            .to_string();

        Ok(DiscoverySelectorProofReport {
            db_path: request.db_path.display().to_string(),
            db_file_size_bytes: db_metadata.len(),
            db_file_mtime_utc,
            db_page_size: db_facts.page_size as u64,
            db_page_count: db_facts.page_count as u64,
            db_read_only_open_confirmed: true,
            config_path: request.config_path.display().to_string(),
            config_fingerprint_method: DISCOVERY_SELECTOR_PROOF_CONFIG_FINGERPRINT_METHOD
                .to_string(),
            config_fingerprint: discovery_selector_proof_config_fingerprint(&request.config_bytes),
            fixed_now_utc: request.fixed_now_utc,
            rpc_enabled: self.helius_http_url.is_some(),
            metrics_window_start_utc: Some(metrics_window_start),
            observed_swaps_loaded: Some(selector_state.observed_swaps_loaded as u64),
            wallets_seen: Some(selector_state.snapshots.len() as u64),
            eligible_wallet_count: Some(ranked.len() as u64),
            observed_swaps_window_min_ts_utc: selector_state.observed_swap_coverage.min_ts_utc,
            observed_swaps_window_max_ts_utc: selector_state.observed_swap_coverage.max_ts_utc,
            observed_swaps_buy_count: selector_state.observed_swap_coverage.buy_count,
            observed_swaps_sell_count: selector_state.observed_swap_coverage.sell_count,
            observed_swaps_distinct_wallet_count: selector_state.snapshots.len() as u64,
            observed_swaps_distinct_buy_mint_count: selector_state
                .token_quality_coverage
                .buy_mints_total,
            wallet_activity_days_window_min_day_utc: wallet_activity_coverage.window_min_day_utc,
            wallet_activity_days_window_max_day_utc: wallet_activity_coverage.window_max_day_utc,
            wallet_activity_days_rows_for_seen_wallets: wallet_activity_coverage
                .rows_for_seen_wallets,
            wallet_activity_days_distinct_wallets_for_seen_wallets: wallet_activity_coverage
                .distinct_wallets_for_seen_wallets,
            wallet_activity_days_min_active_days_among_seen_wallets: wallet_activity_coverage
                .min_active_days_among_seen_wallets,
            wallet_activity_days_max_active_days_among_seen_wallets: wallet_activity_coverage
                .max_active_days_among_seen_wallets,
            token_quality_cache_rows_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .cache_rows_for_seen_buy_mints(),
            token_quality_cache_distinct_mints_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .distinct_mints_for_seen_buy_mints(),
            token_quality_cache_fresh_rows_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .fresh_cache_hits,
            token_quality_cache_stale_rows_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .stale_cache_hits,
            token_quality_cache_missing_rows_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .missing_cache_entries,
            token_quality_cache_min_fetched_at_utc_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .min_fetched_at_utc,
            token_quality_cache_max_fetched_at_utc_for_seen_buy_mints: selector_state
                .token_quality_coverage
                .max_fetched_at_utc,
            ranked_wallets,
            rejected_wallet_sample_limit: SELECTOR_PROOF_REJECTED_WALLET_SAMPLE_LIMIT as u64,
            rejected_wallet_samples,
            reject_breakdown,
            token_quality_coverage: selector_state.token_quality_coverage.to_map(),
            selector_universe_explanation,
        })
    }

    fn selector_proof_reject_breakdown(
        &self,
        outcomes: &[WalletSnapshotOutcome],
        by_wallet: &HashMap<String, WalletAccumulator>,
        token_quality_resolutions: &HashMap<String, quality_cache::TokenQualityResolution>,
    ) -> BTreeMap<String, u64> {
        let mut breakdown = zeroed_u64_map(SELECTOR_PROOF_REJECT_BREAKDOWN_KEYS);
        for outcome in outcomes {
            if outcome.snapshot.eligible && outcome.snapshot.score >= self.config.min_score {
                continue;
            }
            for reason in &outcome.reject_reasons {
                let key = reason.as_str().to_string();
                let entry = breakdown.entry(key).or_insert(0);
                *entry = entry.saturating_add(1);
            }

            let quality_sensitive_rejection = outcome
                .reject_reasons
                .contains(&SelectorRejectReason::LowTradableRatio)
                || outcome
                    .reject_reasons
                    .contains(&SelectorRejectReason::BelowMinScore);
            if !quality_sensitive_rejection {
                continue;
            }

            let Some(acc) = by_wallet.get(&outcome.snapshot.wallet_id) else {
                continue;
            };
            let saw_missing_quality = acc.buy_mints.iter().any(|mint| {
                matches!(
                    token_quality_resolutions.get(mint),
                    Some(quality_cache::TokenQualityResolution::Missing)
                        | Some(quality_cache::TokenQualityResolution::Deferred)
                        | None
                )
            });
            let saw_stale_quality = acc.buy_mints.iter().any(|mint| {
                matches!(
                    token_quality_resolutions.get(mint),
                    Some(quality_cache::TokenQualityResolution::Stale(_))
                )
            });

            if saw_missing_quality {
                let entry = breakdown
                    .entry("missing_token_quality".to_string())
                    .or_insert(0);
                *entry = entry.saturating_add(1);
            }
            if saw_stale_quality {
                let entry = breakdown
                    .entry("stale_token_quality".to_string())
                    .or_insert(0);
                *entry = entry.saturating_add(1);
            }
        }
        breakdown
    }

    fn selector_proof_wallet_activity_coverage(
        &self,
        store: &SqliteStore,
        wallet_ids: &[String],
        window_start: DateTime<Utc>,
    ) -> Result<SelectorProofWalletActivityCoverage> {
        let summary = match store.wallet_activity_day_coverage_since(wallet_ids, window_start) {
            Ok(summary) => summary,
            Err(error) => {
                if discovery_wallet_activity_day_count_error_requires_abort(&error) {
                    return Err(error).context(
                        "failed loading persisted wallet_activity_days coverage with fatal sqlite I/O",
                    );
                }
                warn!(
                    error = %error,
                    wallet_count = wallet_ids.len(),
                    "failed loading persisted wallet_activity_days coverage; returning empty proof coverage"
                );
                return Ok(SelectorProofWalletActivityCoverage::default());
            }
        };
        let counts = self.load_persisted_active_day_counts_for_wallet_ids_since(
            store,
            wallet_ids,
            window_start,
        )?;
        Ok(SelectorProofWalletActivityCoverage {
            window_min_day_utc: summary.window_min_day_utc,
            window_max_day_utc: summary.window_max_day_utc,
            rows_for_seen_wallets: summary.rows_for_wallets,
            distinct_wallets_for_seen_wallets: summary.distinct_wallets_for_wallets,
            min_active_days_among_seen_wallets: counts.values().copied().min(),
            max_active_days_among_seen_wallets: counts.values().copied().max(),
        })
    }

    fn selector_proof_rejected_wallet_samples(
        &self,
        outcomes: &[WalletSnapshotOutcome],
    ) -> Vec<DiscoverySelectorProofRejectedWalletSample> {
        let mut samples: Vec<_> = outcomes
            .iter()
            .filter(|outcome| {
                !(outcome.snapshot.eligible && outcome.snapshot.score >= self.config.min_score)
            })
            .map(|outcome| DiscoverySelectorProofRejectedWalletSample {
                wallet_id: outcome.snapshot.wallet_id.clone(),
                score: outcome.snapshot.score,
                eligible: outcome.snapshot.eligible,
                reject_reasons: outcome
                    .reject_reasons
                    .iter()
                    .map(|reason| reason.as_str().to_string())
                    .collect(),
                active_days: outcome.active_days,
                buy_total: outcome.snapshot.buy_total,
                trades: outcome.snapshot.trades,
                tradable_ratio: outcome.snapshot.tradable_ratio,
                pnl_sol: outcome.snapshot.pnl_sol,
                last_seen_utc: outcome.snapshot.last_seen,
            })
            .collect();
        samples.sort_by(|left, right| left.wallet_id.cmp(&right.wallet_id));
        samples.truncate(SELECTOR_PROOF_REJECTED_WALLET_SAMPLE_LIMIT);
        samples
    }

    fn selector_proof_universe_explanation(
        &self,
        observed_swaps_loaded: u64,
        wallets_seen: u64,
        eligible_wallet_count: u64,
    ) -> &'static str {
        if observed_swaps_loaded == 0 {
            SELECTOR_UNIVERSE_EXPLANATION_EMPTY_NO_OBSERVED_SWAPS
        } else if wallets_seen == 0 {
            SELECTOR_UNIVERSE_EXPLANATION_EMPTY_NO_WALLETS_SEEN
        } else if eligible_wallet_count > 0 {
            SELECTOR_UNIVERSE_EXPLANATION_NON_EMPTY
        } else {
            SELECTOR_UNIVERSE_EXPLANATION_EMPTY_SELECTOR_GATES
        }
    }

    pub fn aggregate_readiness_status(
        &self,
        store: &SqliteStore,
        now: DateTime<Utc>,
    ) -> Result<AggregateReadinessStatus> {
        let window_start = now - Duration::days(self.config.scoring_window_days.max(1) as i64);
        let runtime_gate_max_lag_seconds = self.config.refresh_seconds.max(1);
        let audit_max_lag_seconds = self
            .config
            .metric_snapshot_interval_seconds
            .max(1)
            .saturating_mul(AGGREGATE_READINESS_MAX_LAG_BUCKETS);
        let covered_since = store.load_discovery_scoring_covered_since()?;
        let covered_through_ts = store.load_discovery_scoring_covered_through()?;
        let covered_through_cursor = store.load_discovery_scoring_covered_through_cursor()?;
        let materialization_gap_cursor =
            store.load_discovery_scoring_materialization_gap_cursor()?;
        let backfill_progress = store
            .load_discovery_scoring_backfill_progress()?
            .map(|(start_ts, cursor)| AggregateBackfillProgressStatus { start_ts, cursor });
        let backfill_protected_since =
            store.load_discovery_scoring_backfill_protected_since(now)?;
        let backfill_active = backfill_protected_since.is_some();
        let backfill_resume_required = backfill_progress.is_some() && !backfill_active;

        let scoring_horizon_covered =
            covered_since.is_some_and(|covered_since| covered_since <= window_start);
        let covered_through_lag_seconds = covered_through_ts.map(|covered_through_ts| {
            now.signed_duration_since(covered_through_ts)
                .num_seconds()
                .max(0) as u64
        });
        let covered_through_within_runtime_lag =
            covered_through_cursor
                .as_ref()
                .is_some_and(|covered_through_cursor| {
                    covered_through_cursor.ts_utc
                        + Duration::seconds(runtime_gate_max_lag_seconds as i64)
                        >= now
                });
        let covered_through_within_audit_lag =
            covered_through_lag_seconds.is_some_and(|covered_through_lag_seconds| {
                covered_through_lag_seconds <= audit_max_lag_seconds
            });
        let storage_ready_for_runtime_gate = scoring_horizon_covered
            && materialization_gap_cursor.is_none()
            && covered_through_within_runtime_lag;
        let coverage_markers_pending_backfill_completion = backfill_progress.is_some()
            && (covered_since.is_none() || covered_through_cursor.is_none());

        let mut write_blockers = Vec::new();
        if !self.config.scoring_aggregates_write_enabled {
            write_blockers.push(AggregateReadinessBlocker::WritesDisabledByConfig);
        }
        if covered_through_cursor.is_none() {
            write_blockers.push(if backfill_progress.is_some() {
                AggregateReadinessBlocker::CoveredThroughCursorPendingBackfillCompletion
            } else {
                AggregateReadinessBlocker::MissingCoveredThroughCursor
            });
        }
        if materialization_gap_cursor.is_some() {
            write_blockers.push(AggregateReadinessBlocker::MaterializationGapLatched);
        }
        if backfill_active {
            write_blockers.push(AggregateReadinessBlocker::BackfillInProgress);
        }
        if backfill_resume_required {
            write_blockers.push(AggregateReadinessBlocker::BackfillResumeRequired);
        }

        let mut read_blockers = Vec::new();
        if !self.config.scoring_aggregates_enabled {
            read_blockers.push(AggregateReadinessBlocker::ReadsDisabledByConfig);
        }
        match covered_since {
            None => read_blockers.push(if backfill_progress.is_some() {
                AggregateReadinessBlocker::CoveredSincePendingBackfillCompletion
            } else {
                AggregateReadinessBlocker::MissingCoveredSince
            }),
            Some(covered_since) if covered_since > window_start => {
                read_blockers.push(AggregateReadinessBlocker::CoveredSinceAfterWindowStart);
            }
            Some(_) => {}
        }
        if covered_through_cursor.is_none() {
            read_blockers.push(if backfill_progress.is_some() {
                AggregateReadinessBlocker::CoveredThroughCursorPendingBackfillCompletion
            } else {
                AggregateReadinessBlocker::MissingCoveredThroughCursor
            });
        } else if !covered_through_within_runtime_lag {
            read_blockers.push(AggregateReadinessBlocker::CoveredThroughTooStaleForRuntimeGate);
        }
        if materialization_gap_cursor.is_some() {
            read_blockers.push(AggregateReadinessBlocker::MaterializationGapLatched);
        }
        if covered_through_ts.is_some() && !covered_through_within_audit_lag {
            read_blockers.push(AggregateReadinessBlocker::CoveredThroughTooStaleForAuditLag);
        }
        if backfill_active {
            read_blockers.push(AggregateReadinessBlocker::BackfillInProgress);
        }
        if backfill_resume_required {
            read_blockers.push(AggregateReadinessBlocker::BackfillResumeRequired);
        }

        Ok(AggregateReadinessStatus {
            window_start,
            writes_enabled: self.config.scoring_aggregates_write_enabled,
            reads_enabled: self.config.scoring_aggregates_enabled,
            runtime_gate_max_lag_seconds,
            audit_max_lag_buckets: AGGREGATE_READINESS_MAX_LAG_BUCKETS,
            audit_max_lag_seconds,
            covered_since,
            covered_through_ts,
            covered_through_cursor,
            covered_through_lag_seconds,
            materialization_gap_cursor,
            backfill_progress,
            backfill_protected_since,
            backfill_active,
            backfill_resume_required,
            coverage_markers_pending_backfill_completion,
            scoring_horizon_covered,
            covered_through_within_runtime_lag,
            covered_through_within_audit_lag,
            storage_ready_for_runtime_gate,
            effective_writes_ready: write_blockers.is_empty(),
            effective_reads_ready: self.config.scoring_aggregates_enabled
                && storage_ready_for_runtime_gate
                && read_blockers.is_empty(),
            write_blockers,
            read_blockers,
        })
    }

    pub fn published_universe_max_age(&self) -> Duration {
        self.publication_freshness_gate()
            .published_universe_max_age()
    }

    pub fn runtime_published_universe_max_age(&self) -> Duration {
        self.published_universe_max_age()
    }

    pub fn publication_freshness_gate(&self) -> DiscoveryPublicationFreshnessGate {
        DiscoveryPublicationFreshnessGate {
            scoring_window_days: self.runtime_scoring_window_days(),
            metric_snapshot_interval_seconds: self.runtime_metric_snapshot_interval_seconds(),
            refresh_seconds: self.config.refresh_seconds,
        }
    }

    pub fn runtime_scoring_window_days(&self) -> i64 {
        self.config.scoring_window_days as i64
    }

    pub fn runtime_metric_snapshot_interval_seconds(&self) -> u64 {
        self.config.metric_snapshot_interval_seconds
    }

    fn publication_selection_policy_fingerprint(&self) -> String {
        format!(
            concat!(
                "follow_top_n={};",
                "scoring_window_days={};",
                "decay_window_days={};",
                "min_leader_notional_sol={:.6};",
                "min_trades={};",
                "min_active_days={};",
                "min_score={:.6};",
                "max_tx_per_minute={};",
                "min_buy_count={};",
                "min_tradable_ratio={:.6};",
                "require_open_positions_for_publication={};",
                "max_rug_ratio={:.6};",
                "rug_lookahead_seconds={};",
                "thin_market_min_volume_sol={:.6};",
                "thin_market_min_unique_traders={}"
            ),
            self.config.follow_top_n,
            self.config.scoring_window_days,
            self.config.decay_window_days,
            self.config.min_leader_notional_sol,
            self.config.min_trades,
            self.config.min_active_days,
            self.config.min_score,
            self.config.max_tx_per_minute,
            self.config.min_buy_count,
            self.config.min_tradable_ratio,
            self.config.require_open_positions_for_publication,
            self.config.max_rug_ratio,
            self.config.rug_lookahead_seconds,
            self.config.thin_market_min_volume_sol,
            self.config.thin_market_min_unique_traders,
        )
    }

    fn invalidate_incompatible_recent_publication_truth_if_needed(
        &self,
        store: &SqliteStore,
        now: DateTime<Utc>,
    ) -> Result<bool> {
        let Some((publication_state, stored_policy_fingerprint)) =
            store.discovery_publication_state_with_policy_read_only()?
        else {
            return Ok(false);
        };
        if publication_state.runtime_mode == DiscoveryRuntimeMode::FailClosed {
            return Ok(false);
        }
        if Self::runtime_publication_truth_from_state(publication_state.clone()).is_none() {
            return Ok(false);
        }

        let current_policy_fingerprint = self.publication_selection_policy_fingerprint();
        if stored_policy_fingerprint.as_deref() == Some(current_policy_fingerprint.as_str()) {
            return Ok(false);
        }

        let reason = "publication_truth_invalidated_selection_policy_mismatch";
        warn!(
            publication_truth_invalidated_selection_policy_mismatch = true,
            publication_previous_runtime_mode = publication_state.runtime_mode.as_str(),
            publication_previous_reason = publication_state.reason.as_str(),
            publication_previous_last_published_at = ?publication_state.last_published_at,
            publication_previous_published_wallet_count = publication_state
                .published_wallet_ids
                .as_ref()
                .map_or(0, |wallets| wallets.len()),
            publication_previous_policy_fingerprint =
                stored_policy_fingerprint.as_deref(),
            publication_current_policy_fingerprint =
                current_policy_fingerprint.as_str(),
            "invalidating recent exact publication truth because the current discovery selection policy no longer matches the policy that produced the published universe"
        );
        store.persist_discovery_cycle(&[], &[], &[], false, false, now, reason)?;
        store.set_discovery_publication_state_with_options(
            &DiscoveryPublicationStateUpdate {
                runtime_mode: DiscoveryRuntimeMode::FailClosed,
                reason: reason.to_string(),
                last_published_at: None,
                last_published_window_start: None,
                published_scoring_source: publication_state.published_scoring_source.clone(),
                published_wallet_ids: None,
            },
            true,
            None,
        )?;
        Ok(true)
    }

    fn runtime_publication_truth_from_state(
        publication_state: DiscoveryPublicationStateRow,
    ) -> Option<RuntimePublishedUniverseTruth> {
        Some(RuntimePublishedUniverseTruth {
            runtime_mode: publication_state.runtime_mode,
            reason: publication_state.reason,
            last_published_at: publication_state.last_published_at?,
            last_published_window_start: publication_state.last_published_window_start?,
            published_scoring_source: publication_state.published_scoring_source,
            published_wallet_ids: publication_state
                .published_wallet_ids
                .filter(|wallet_ids| !wallet_ids.is_empty())?,
        })
    }

    pub fn runtime_publication_truth_resolution(
        &self,
        store: &SqliteStore,
        now: DateTime<Utc>,
    ) -> Result<Option<RuntimePublicationTruthResolution>> {
        if self.invalidate_incompatible_recent_publication_truth_if_needed(store, now)? {
            return Ok(None);
        }
        let Some(publication_state) = store.discovery_publication_state_read_only()? else {
            return Ok(None);
        };
        if publication_state.runtime_mode == DiscoveryRuntimeMode::FailClosed {
            return Ok(None);
        }
        let Some(runtime_truth) =
            Self::runtime_publication_truth_from_state(publication_state.clone())
        else {
            return Ok(None);
        };
        if publication_state.is_fresh_under_gate(self.publication_freshness_gate(), now) {
            return Ok(Some(RuntimePublicationTruthResolution::Recent(
                runtime_truth,
            )));
        }
        if store.discovery_bootstrap_degraded_state_read_only()?.active {
            let mut bootstrap_runtime_truth = runtime_truth;
            bootstrap_runtime_truth.runtime_mode = DiscoveryRuntimeMode::BootstrapDegraded;
            return Ok(Some(RuntimePublicationTruthResolution::BootstrapDegraded(
                bootstrap_runtime_truth,
            )));
        }
        Ok(None)
    }

    pub fn recent_runtime_publication_truth(
        &self,
        store: &SqliteStore,
        now: DateTime<Utc>,
    ) -> Result<Option<RuntimePublishedUniverseTruth>> {
        Ok(
            match self.runtime_publication_truth_resolution(store, now)? {
                Some(RuntimePublicationTruthResolution::Recent(truth)) => Some(truth),
                Some(RuntimePublicationTruthResolution::BootstrapDegraded(_)) | None => None,
            },
        )
    }

    pub fn bootstrap_degraded_runtime_publication_truth(
        &self,
        store: &SqliteStore,
        now: DateTime<Utc>,
    ) -> Result<Option<RuntimePublishedUniverseTruth>> {
        Ok(
            match self.runtime_publication_truth_resolution(store, now)? {
                Some(RuntimePublicationTruthResolution::BootstrapDegraded(truth)) => Some(truth),
                Some(RuntimePublicationTruthResolution::Recent(_)) | None => None,
            },
        )
    }

    pub fn recent_published_follow_universe_wallets(
        &self,
        store: &SqliteStore,
        now: DateTime<Utc>,
    ) -> Result<Option<HashSet<String>>> {
        Ok(self
            .recent_runtime_publication_truth(store, now)?
            .map(|truth| truth.active_wallets()))
    }

