    #[derive(Debug, PartialEq, Eq)]
    struct PostRebuildGateAttributionCounts {
        wallets_seen: usize,
        before_actionable_open_position_gate: usize,
        after_actionable_open_position_gate: usize,
        after_rug_gate: usize,
        after_score_min_filters: usize,
        after_ranking_top_n: usize,
    }

    fn post_rebuild_gate_attribution_counts_for_store_backed_lineage(
        discovery: &DiscoveryService,
        store: &SqliteStore,
        by_wallet: &HashMap<String, WalletAccumulator>,
        now: DateTime<Utc>,
    ) -> Result<PostRebuildGateAttributionCounts> {
        let wallet_ids: Vec<String> = by_wallet.keys().cloned().collect();
        let persisted_active_day_counts =
            discovery.load_persisted_active_day_counts_for_wallet_ids(store, &wallet_ids, now)?;
        let empty_token_sol_history = HashMap::new();
        let mut before_actionable_open_position_gate = 0usize;
        let mut counterfactual_open_gate_candidate_wallet_ids = Vec::new();
        for (wallet_id, acc) in by_wallet {
            let persisted_active_days = persisted_active_day_counts
                .get(wallet_id)
                .copied()
                .unwrap_or(0);
            let snapshot = discovery
                .snapshot_outcome_from_accumulator_with_persisted_active_days_internal(
                    wallet_id.clone(),
                    acc.clone(),
                    now,
                    &empty_token_sol_history,
                    persisted_active_days,
                    false,
                    true,
                )
                .snapshot;
            if snapshot.eligible && snapshot.score >= discovery.config.min_score {
                before_actionable_open_position_gate =
                    before_actionable_open_position_gate.saturating_add(1);
                counterfactual_open_gate_candidate_wallet_ids.push(wallet_id.clone());
            }
        }

        let reconstructed_positions_by_wallet = discovery
            .reconstruct_retention_window_positions_for_wallets(
                store,
                &counterfactual_open_gate_candidate_wallet_ids,
                now,
            )?;
        let mut after_actionable_open_position_gate = 0usize;
        for wallet_id in counterfactual_open_gate_candidate_wallet_ids {
            let Some(acc) = by_wallet.get(&wallet_id) else {
                continue;
            };
            let mut gated_acc = acc.clone();
            if let Some(reconstructed_positions) = reconstructed_positions_by_wallet.get(&wallet_id)
            {
                gated_acc.positions = reconstructed_positions.clone();
            }
            let persisted_active_days = persisted_active_day_counts
                .get(&wallet_id)
                .copied()
                .unwrap_or(0);
            let snapshot = discovery
                .snapshot_outcome_from_accumulator_with_persisted_active_days_internal(
                    wallet_id,
                    gated_acc,
                    now,
                    &empty_token_sol_history,
                    persisted_active_days,
                    true,
                    true,
                )
                .snapshot;
            if snapshot.eligible && snapshot.score >= discovery.config.min_score {
                after_actionable_open_position_gate =
                    after_actionable_open_position_gate.saturating_add(1);
            }
        }

        let current_snapshots = discovery.wallet_snapshots_from_accumulators(
            store,
            by_wallet.clone(),
            now,
            &empty_token_sol_history,
        )?;
        let after_rug_gate = current_snapshots
            .iter()
            .filter(|snapshot| snapshot.eligible)
            .count();
        let ranked = rank_follow_candidates(&current_snapshots, discovery.config.min_score);
        let after_score_min_filters = ranked.len();
        let after_ranking_top_n = desired_wallets(&ranked, discovery.config.follow_top_n).len();

        Ok(PostRebuildGateAttributionCounts {
            wallets_seen: by_wallet.len(),
            before_actionable_open_position_gate,
            after_actionable_open_position_gate,
            after_rug_gate,
            after_score_min_filters,
            after_ranking_top_n,
        })
    }

    #[derive(Debug, PartialEq, Eq)]
    struct LivePublishGateAttributionCounts {
        total_snapshots: usize,
        removed_by_min_trades: usize,
        removed_by_min_active_days: usize,
        removed_by_suspicious: usize,
        removed_by_min_leader_notional_sol: usize,
        removed_by_decay_window_days: usize,
        removed_by_min_buy_count: usize,
        removed_by_min_tradable_ratio: usize,
        removed_by_min_score: usize,
        published_wallets: usize,
    }

    fn live_publish_gate_attribution_counts(
        config: &DiscoveryConfig,
        entries: &[(String, WalletAccumulator)],
        snapshots: &[WalletSnapshot],
        now: DateTime<Utc>,
    ) -> LivePublishGateAttributionCounts {
        let snapshot_by_wallet: HashMap<&str, &WalletSnapshot> = snapshots
            .iter()
            .map(|snapshot| (snapshot.wallet_id.as_str(), snapshot))
            .collect();
        let total_snapshots = entries.len();
        let mut remaining: Vec<(&String, &WalletAccumulator)> = entries
            .iter()
            .map(|(wallet_id, acc)| (wallet_id, acc))
            .collect();

        let before = remaining.len();
        remaining.retain(|(_, acc)| acc.trades >= config.min_trades);
        let removed_by_min_trades = before - remaining.len();

        let before = remaining.len();
        remaining.retain(|(_, acc)| {
            let active_days = acc
                .exact_active_day_count
                .unwrap_or(acc.active_days.len() as u32);
            active_days >= config.min_active_days
        });
        let removed_by_min_active_days = before - remaining.len();

        let before = remaining.len();
        remaining.retain(|(_, acc)| !acc.suspicious);
        let removed_by_suspicious = before - remaining.len();

        let before = remaining.len();
        remaining.retain(|(_, acc)| acc.max_buy_notional_sol >= config.min_leader_notional_sol);
        let removed_by_min_leader_notional_sol = before - remaining.len();

        let decay_cutoff = now - Duration::days(config.decay_window_days.max(1) as i64);
        let before = remaining.len();
        remaining.retain(|(_, acc)| acc.last_seen.unwrap_or(now) >= decay_cutoff);
        let removed_by_decay_window_days = before - remaining.len();

        let before = remaining.len();
        remaining.retain(|(wallet_id, _)| {
            snapshot_by_wallet
                .get(wallet_id.as_str())
                .is_some_and(|snapshot| snapshot.buy_total >= config.min_buy_count)
        });
        let removed_by_min_buy_count = before - remaining.len();

        let before = remaining.len();
        remaining.retain(|(wallet_id, _)| {
            snapshot_by_wallet
                .get(wallet_id.as_str())
                .is_some_and(|snapshot| snapshot.tradable_ratio >= config.min_tradable_ratio)
        });
        let removed_by_min_tradable_ratio = before - remaining.len();

        let before = remaining.len();
        remaining.retain(|(wallet_id, _)| {
            snapshot_by_wallet
                .get(wallet_id.as_str())
                .is_some_and(|snapshot| snapshot.score >= config.min_score)
        });
        let removed_by_min_score = before - remaining.len();

        LivePublishGateAttributionCounts {
            total_snapshots,
            removed_by_min_trades,
            removed_by_min_active_days,
            removed_by_suspicious,
            removed_by_min_leader_notional_sol,
            removed_by_decay_window_days,
            removed_by_min_buy_count,
            removed_by_min_tradable_ratio,
            removed_by_min_score,
            published_wallets: remaining.len(),
        }
    }

    #[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
    enum LivePublishGateRelaxation {
        MinActiveDays,
        MinLeaderNotionalSol,
        DecayWindowDays,
        MinBuyCount,
        MinTradableRatio,
        MinScore,
        Suspicious,
    }

    impl LivePublishGateRelaxation {
        fn label(self) -> &'static str {
            match self {
                Self::MinActiveDays => "min_active_days",
                Self::MinLeaderNotionalSol => "min_leader_notional_sol",
                Self::DecayWindowDays => "decay_window_days",
                Self::MinBuyCount => "min_buy_count",
                Self::MinTradableRatio => "min_tradable_ratio",
                Self::MinScore => "min_score",
                Self::Suspicious => "suspicious",
            }
        }
    }

    fn relaxed_live_shadow_blocker_config_for_tests(
        base: &DiscoveryConfig,
        relaxations: &[LivePublishGateRelaxation],
    ) -> DiscoveryConfig {
        let mut config = base.clone();
        for relaxation in relaxations {
            match relaxation {
                LivePublishGateRelaxation::MinActiveDays => config.min_active_days = 2,
                LivePublishGateRelaxation::MinLeaderNotionalSol => {
                    config.min_leader_notional_sol = 0.4;
                }
                LivePublishGateRelaxation::DecayWindowDays => config.decay_window_days = 7,
                LivePublishGateRelaxation::MinBuyCount => config.min_buy_count = 9,
                LivePublishGateRelaxation::MinTradableRatio => config.min_tradable_ratio = 0.0,
                LivePublishGateRelaxation::MinScore => config.min_score = 0.0,
                LivePublishGateRelaxation::Suspicious => {}
            }
        }
        config
    }

    fn live_publish_gate_fixture_with_relaxations(
        base_entries: &[(String, WalletAccumulator)],
        relaxations: &[LivePublishGateRelaxation],
    ) -> Vec<(String, WalletAccumulator)> {
        let mut entries = base_entries.to_vec();
        if relaxations.contains(&LivePublishGateRelaxation::Suspicious) {
            let (_, suspicious_acc) = entries
                .iter_mut()
                .find(|(wallet_id, _)| wallet_id == "wallet_fail_suspicious")
                .expect("suspicious fixture wallet should exist");
            suspicious_acc.suspicious = false;
        }
        entries
    }

    fn live_publish_gate_desired_wallets_for_relaxations(
        base_config: &DiscoveryConfig,
        base_entries: &[(String, WalletAccumulator)],
        relaxations: &[LivePublishGateRelaxation],
        now: DateTime<Utc>,
    ) -> Vec<String> {
        let config = relaxed_live_shadow_blocker_config_for_tests(base_config, relaxations);
        let entries = live_publish_gate_fixture_with_relaxations(base_entries, relaxations);
        let (_, desired) = desired_wallets_from_live_publish_gate_fixture(config, &entries, now);
        desired
    }

    fn live_restored_rug_policy_discovery_config_for_tests() -> DiscoveryConfig {
        let mut config = live_shadow_blocker_discovery_config_for_tests();
        let defaults = DiscoveryConfig::default();
        config.max_rug_ratio = defaults.max_rug_ratio;
        config.thin_market_min_volume_sol = defaults.thin_market_min_volume_sol;
        config.thin_market_min_unique_traders = defaults.thin_market_min_unique_traders;
        config
    }

    fn clustered_thin_market_fixture_swaps(
        now: DateTime<Utc>,
        include_independent_wallets: bool,
    ) -> (Vec<SwapEvent>, Vec<String>, Vec<String>) {
        let clustered_wallet_ids: Vec<String> = (0..9)
            .map(|idx| format!("wallet_clustered_{idx:02}"))
            .collect();
        let independent_wallet_ids: Vec<String> = if include_independent_wallets {
            (0..3)
                .map(|idx| format!("wallet_independent_{idx:02}"))
                .collect()
        } else {
            Vec::new()
        };
        let clustered_token = "TokenClusteredVdor111111111111111111111111";
        let phase_bases = [
            now - Duration::days(2),
            now - Duration::days(1),
            now - Duration::hours(2),
        ];
        let rounds_per_phase = 4;
        let mut swaps = Vec::new();

        for (phase_idx, phase_base) in phase_bases.into_iter().enumerate() {
            for round in 0..rounds_per_phase {
                let round_offset_minutes = (round * 20) as i64;
                for (wallet_idx, wallet_id) in clustered_wallet_ids.iter().enumerate() {
                    let buy_ts =
                        phase_base + Duration::minutes(round_offset_minutes + wallet_idx as i64);
                    let sell_ts = buy_ts + Duration::minutes(5);
                    swaps.push(swap(
                        wallet_id,
                        &format!("clustered-{phase_idx}-{round}-{wallet_idx}-buy"),
                        buy_ts,
                        SOL_MINT,
                        clustered_token,
                        1.0,
                        100.0,
                    ));
                    swaps.push(swap(
                        wallet_id,
                        &format!("clustered-{phase_idx}-{round}-{wallet_idx}-sell"),
                        sell_ts,
                        clustered_token,
                        SOL_MINT,
                        100.0,
                        1.3,
                    ));
                }

                for (wallet_idx, wallet_id) in independent_wallet_ids.iter().enumerate() {
                    let token = format!("TokenIndependent{wallet_idx:02}11111111111111111111");
                    let buy_ts = phase_base
                        + Duration::minutes(round_offset_minutes + 12 + wallet_idx as i64);
                    let sell_ts = buy_ts + Duration::minutes(5);
                    swaps.push(swap(
                        wallet_id,
                        &format!("independent-{phase_idx}-{round}-{wallet_idx}-buy"),
                        buy_ts,
                        SOL_MINT,
                        token.as_str(),
                        1.0,
                        100.0,
                    ));
                    swaps.push(swap(
                        wallet_id,
                        &format!("independent-{phase_idx}-{round}-{wallet_idx}-sell"),
                        sell_ts,
                        token.as_str(),
                        SOL_MINT,
                        100.0,
                        1.25,
                    ));
                    for noise_idx in 0..10 {
                        swaps.push(swap(
                            &format!(
                                "wallet_independent_noise_{phase_idx:02}_{round:02}_{wallet_idx:02}_{noise_idx:02}"
                            ),
                            &format!(
                                "independent-noise-{phase_idx}-{round}-{wallet_idx}-{noise_idx}"
                            ),
                            buy_ts + Duration::seconds(30 + noise_idx as i64),
                            SOL_MINT,
                            token.as_str(),
                            0.4,
                            40.0,
                        ));
                    }
                }
            }
        }

        swaps.sort_by(|a, b| {
            a.ts_utc
                .cmp(&b.ts_utc)
                .then_with(|| a.signature.cmp(&b.signature))
        });
        (swaps, clustered_wallet_ids, independent_wallet_ids)
    }

    fn clustered_partial_survival_fixture_swaps(
        now: DateTime<Utc>,
        include_independent_wallets_with_open_positions: bool,
    ) -> (Vec<SwapEvent>, Vec<String>, Vec<String>, Vec<String>) {
        let removed_wallet_ids: Vec<String> = (0..3)
            .map(|idx| format!("wallet_clustered_removed_{idx:02}"))
            .collect();
        let surviving_wallet_ids: Vec<String> = (0..6)
            .map(|idx| format!("wallet_clustered_surviving_{idx:02}"))
            .collect();
        let independent_wallet_ids: Vec<String> = if include_independent_wallets_with_open_positions
        {
            (0..3)
                .map(|idx| format!("wallet_independent_open_{idx:02}"))
                .collect()
        } else {
            Vec::new()
        };
        let removed_token = "TokenClusteredThinEdge111111111111111111111";
        let surviving_token = "TokenClusteredThickEdge11111111111111111111";
        let phase_bases = [
            now - Duration::days(2),
            now - Duration::days(1),
            now - Duration::hours(2),
        ];
        let rounds_per_phase = 4;
        let mut swaps = Vec::new();

        for (phase_idx, phase_base) in phase_bases.into_iter().enumerate() {
            for round in 0..rounds_per_phase {
                let round_offset_minutes = (round * 20) as i64;

                for (wallet_idx, wallet_id) in removed_wallet_ids.iter().enumerate() {
                    let buy_ts =
                        phase_base + Duration::minutes(round_offset_minutes + wallet_idx as i64);
                    let sell_ts = buy_ts + Duration::minutes(5);
                    swaps.push(swap(
                        wallet_id,
                        &format!("removed-{phase_idx}-{round}-{wallet_idx}-buy"),
                        buy_ts,
                        SOL_MINT,
                        removed_token,
                        1.0,
                        100.0,
                    ));
                    swaps.push(swap(
                        wallet_id,
                        &format!("removed-{phase_idx}-{round}-{wallet_idx}-sell"),
                        sell_ts,
                        removed_token,
                        SOL_MINT,
                        100.0,
                        1.3,
                    ));
                }

                for (wallet_idx, wallet_id) in surviving_wallet_ids.iter().enumerate() {
                    let buy_ts = phase_base
                        + Duration::minutes(round_offset_minutes + 6 + wallet_idx as i64);
                    let sell_ts = buy_ts + Duration::minutes(5);
                    swaps.push(swap(
                        wallet_id,
                        &format!("surviving-{phase_idx}-{round}-{wallet_idx}-buy"),
                        buy_ts,
                        SOL_MINT,
                        surviving_token,
                        1.0,
                        100.0,
                    ));
                    swaps.push(swap(
                        wallet_id,
                        &format!("surviving-{phase_idx}-{round}-{wallet_idx}-sell"),
                        sell_ts,
                        surviving_token,
                        SOL_MINT,
                        100.0,
                        1.3,
                    ));
                }

                for noise_idx in 0..4 {
                    let noise_buy_ts = phase_base
                        + Duration::minutes(round_offset_minutes + 14 + noise_idx as i64);
                    swaps.push(swap(
                        &format!(
                            "wallet_clustered_surviving_noise_{phase_idx:02}_{round:02}_{noise_idx:02}"
                        ),
                        &format!("surviving-noise-{phase_idx}-{round}-{noise_idx}"),
                        noise_buy_ts,
                        SOL_MINT,
                        surviving_token,
                        0.4,
                        40.0,
                    ));
                }

                for (wallet_idx, wallet_id) in independent_wallet_ids.iter().enumerate() {
                    let token = format!("TokenIndependentOpen{wallet_idx:02}111111111111111111");
                    let buy_ts = phase_base
                        + Duration::minutes(round_offset_minutes + 22 + wallet_idx as i64);
                    let final_round =
                        phase_idx == phase_bases.len() - 1 && round == rounds_per_phase - 1;
                    swaps.push(swap(
                        wallet_id,
                        &format!("independent-open-{phase_idx}-{round}-{wallet_idx}-buy"),
                        buy_ts,
                        SOL_MINT,
                        token.as_str(),
                        1.0,
                        100.0,
                    ));
                    if !final_round {
                        swaps.push(swap(
                            wallet_id,
                            &format!("independent-open-{phase_idx}-{round}-{wallet_idx}-sell"),
                            buy_ts + Duration::minutes(5),
                            token.as_str(),
                            SOL_MINT,
                            100.0,
                            1.25,
                        ));
                    }
                    for noise_idx in 0..10 {
                        swaps.push(swap(
                            &format!(
                                "wallet_independent_open_noise_{phase_idx:02}_{round:02}_{wallet_idx:02}_{noise_idx:02}"
                            ),
                            &format!(
                                "independent-open-noise-{phase_idx}-{round}-{wallet_idx}-{noise_idx}"
                            ),
                            buy_ts + Duration::seconds(30 + noise_idx as i64),
                            SOL_MINT,
                            token.as_str(),
                            0.4,
                            40.0,
                        ));
                    }
                }
            }
        }

        swaps.sort_by(|a, b| {
            a.ts_utc
                .cmp(&b.ts_utc)
                .then_with(|| a.signature.cmp(&b.signature))
        });
        (
            swaps,
            removed_wallet_ids,
            surviving_wallet_ids,
            independent_wallet_ids,
        )
    }

    fn sol_leg_window_volume_and_unique_traders(
        token_sol_history: &HashMap<String, Vec<SolLegTrade>>,
        token: &str,
        window_start: DateTime<Utc>,
        window_end: DateTime<Utc>,
    ) -> (f64, usize) {
        let Some(trades) = token_sol_history.get(token) else {
            return (0.0, 0);
        };
        let mut volume_sol = 0.0;
        let mut unique_traders = HashSet::new();
        for trade in trades {
            if trade.ts < window_start || trade.ts > window_end {
                continue;
            }
            volume_sol += trade.sol_notional;
            unique_traders.insert(trade.wallet_id.as_str());
        }
        (volume_sol, unique_traders.len())
    }

    fn wallet_entries_and_token_history_from_swaps(
        config: &DiscoveryConfig,
        swaps: &[SwapEvent],
    ) -> (
        Vec<(String, WalletAccumulator)>,
        HashMap<String, Vec<SolLegTrade>>,
    ) {
        let mut by_wallet: HashMap<String, WalletAccumulator> = HashMap::new();
        let mut token_sol_history: HashMap<String, Vec<SolLegTrade>> = HashMap::new();

        for swap in swaps {
            by_wallet
                .entry(swap.wallet.clone())
                .or_default()
                .observe_swap(
                    swap,
                    config.max_tx_per_minute,
                    is_sol_buy(swap).then_some(BuyTradability::Tradable),
                    false,
                );
            if let Some(token) = sol_leg_token(swap) {
                token_sol_history
                    .entry(token.to_string())
                    .or_default()
                    .push(SolLegTrade {
                        ts: swap.ts_utc,
                        wallet_id: swap.wallet.clone(),
                        sol_notional: if is_sol_buy(swap) {
                            swap.amount_in
                        } else {
                            swap.amount_out
                        },
                    });
            }
        }

        for trades in token_sol_history.values_mut() {
            trades.sort_by(|a, b| a.ts.cmp(&b.ts).then_with(|| a.wallet_id.cmp(&b.wallet_id)));
        }

        let mut entries: Vec<(String, WalletAccumulator)> = by_wallet.into_iter().collect();
        entries.sort_by(|a, b| a.0.cmp(&b.0));
        (entries, token_sol_history)
    }

    fn desired_wallets_from_clustered_thin_market_fixture(
        config: DiscoveryConfig,
        swaps: &[SwapEvent],
        now: DateTime<Utc>,
    ) -> (
        Vec<WalletSnapshot>,
        Vec<String>,
        Vec<(String, WalletAccumulator)>,
        HashMap<String, Vec<SolLegTrade>>,
    ) {
        let (entries, token_sol_history) =
            wallet_entries_and_token_history_from_swaps(&config, swaps);
        let discovery = DiscoveryService::new(config.clone(), permissive_shadow_quality());
        let snapshots = entries
            .iter()
            .map(|(wallet_id, acc)| {
                discovery.snapshot_from_accumulator(
                    wallet_id.clone(),
                    acc.clone(),
                    now,
                    &token_sol_history,
                )
            })
            .collect::<Vec<_>>();
        let ranked = rank_follow_candidates(&snapshots, config.min_score);
        let desired = desired_wallets(&ranked, config.follow_top_n);
        (snapshots, desired, entries, token_sol_history)
    }

    fn seed_stage1_persisted_stream_runtime_fixture(
        store: &SqliteStore,
        config: &DiscoveryConfig,
        now: DateTime<Utc>,
        profitable_pairs: usize,
        tail_noise_rows: usize,
    ) -> Result<(DateTime<Utc>, DateTime<Utc>)> {
        let window_start = now - Duration::days(config.scoring_window_days.max(1) as i64);
        let metrics_window_start = metrics_window_start_for_test(config, now);

        for idx in 0..profitable_pairs {
            let offset = Duration::minutes((idx * 20) as i64);
            let token = format!("TokenStage1PersistedTop{idx:02}111111111111111111111");
            store.insert_observed_swap(&swap(
                "wallet_top",
                &format!("stage1-persisted-top-buy-{idx}"),
                window_start + offset,
                SOL_MINT,
                token.as_str(),
                1.0,
                100.0,
            ))?;
            store.insert_observed_swap(&swap(
                "wallet_top",
                &format!("stage1-persisted-top-sell-{idx}"),
                window_start + offset + Duration::minutes(5),
                token.as_str(),
                SOL_MINT,
                100.0,
                1.3,
            ))?;
            store.insert_observed_swap(&swap(
                "wallet_noise",
                &format!("stage1-persisted-noise-early-buy-{idx}"),
                window_start + offset,
                SOL_MINT,
                token.as_str(),
                1.0,
                100.0,
            ))?;
            store.insert_observed_swap(&swap(
                "wallet_noise",
                &format!("stage1-persisted-noise-early-sell-{idx}"),
                window_start + offset + Duration::minutes(5),
                token.as_str(),
                SOL_MINT,
                100.0,
                0.7,
            ))?;
        }

        let mut latest_cursor: Option<DiscoveryRuntimeCursor> = None;
        for idx in 0..tail_noise_rows {
            let ts =
                now - Duration::minutes(tail_noise_rows as i64) + Duration::minutes(idx as i64);
            let swap = swap(
                "wallet_tail_noise",
                &format!("stage1-persisted-tail-noise-{idx}"),
                ts,
                SOL_MINT,
                "TokenStage1PersistedNoise1111111111111111",
                0.2,
                20.0,
            );
            latest_cursor = Some(DiscoveryRuntimeCursor {
                ts_utc: swap.ts_utc,
                slot: swap.slot,
                signature: swap.signature.clone(),
            });
            store.insert_observed_swap(&swap)?;
        }
        store.upsert_discovery_runtime_cursor(
            &latest_cursor.expect("latest cursor should be present"),
        )?;

        Ok((window_start, metrics_window_start))
    }

